// 웨스트민스터 대요리문답 (Westminster Larger Catechism) — 전 196문답
// 질문·답 본문: 리고니어 미니스트리 한국어 공개본
//   https://ko.ligonier.org/resources/creeds-and-confessions/the-westminster-larger-catechism/
// 성경 증거구절(references): 대한예수교장로회(KAPC) 공개본 https://kapc.org/대요리-문답/ (문답 번호로 매칭)

import type { CatechismItem } from './westminsterShorter';

export type { CatechismItem };

export const largerCatechism: CatechismItem[] = [
  { number: 1, question: "사람의 제일 되고 가장 높은 목적이 무엇입니까?", answer: "사람의 제일 되고 가장 높은 목적은 하나님을 영화롭게 하고, 하나님을 영원토록 충만히 즐거워하는 것입니다.", references: ["롬 11:36", "고전 10:31", "시 73:24∼28", "요 17:21∼23"] },
  { number: 2, question: "하나님께서 계시는 사실이 어떻게 나타납니까?", answer: "사람의 본성의 빛과 하나님의 일들이 하나님께서 계신 것을 명백히 나타내지만, 하나님의 말씀과 성신만이 사람의 구원을 위하여 하나님을 사람들에게 충분하고 효과 있게 계시하십니다.", references: ["롬 1:19-20", "시 19:1-3", "행 17:28", "고전 2:9-10", "딤후 3:15-17", "사 59:21"] },
  { number: 3, question: "하나님의 말씀이 무엇입니까?", answer: "구약과 신약에 있는 거룩한 책들이 하나님의 말씀이며 믿음과 순종의 유일한 준칙입니다.", references: ["딤후 3:16", "벧후 1:19∼21", "엡 2:20", "계 22:18∼19", "사 8:20", "눅 16:29, 31", "갈 1:8∼9", "딤후 3:15∼16"] },
  { number: 4, question: "성경이 하나님의 말씀인 것이 어떻게 나타납니까?", answer: "성경은 그 장엄성과 순수성, 모든 부분의 일치성, (모든 영광을 하나님께 돌리는) 성경 전체의 목적, 죄인들을 깨닫게 하여 돌이키게 하고 신자를 위로하고 세워서 구원에 이르게 하는 그 빛과 능력에 의하여 하나님의 말씀으로 명백히 드러납니다. 그러나 성경으로 또한 성경과 함께 사람의 마음속에서 증언하시는 하나님의 성신께서만 성경이 하나님의 말씀임을 완전히 수긍하게 하실 수 있습니다.", references: ["호 8:12", "고전 2:6∼7", "시 119:18, 129", "시 12:6", "시 19:7∼9", "롬 15:4", "행 20:32", "요 16:13∼14", "요일 2:20, 27", "요 20:31"] },
  { number: 5, question: "성경이 가장 중요하게 가르치는 것이 무엇입니까?", answer: "성경이 가장 중요하게 가르치는 것은 사람이 하나님에 대하여 믿을 것은 무엇이며, 하나님께서 사람에게 요구하시는 본분은 무엇인가 하는 것입니다.", references: ["딤후 1:13"] },
  { number: 6, question: "성경이 하나님에 대하여 알려주는 것이 무엇입니까?", answer: "성경은 하나님께서 어떤 분이신가와 하나님 안의 위격(位格)들과 하나님의 작정(作定)과 그 작정의 집행을 알려줍니다.", references: ["히 11:6", "요일 5:7", "행 15:14, 15, 18", "행 4:27∼28"] },
  { number: 7, question: "하나님께서는 어떤 분이십니까?", answer: "하나님께서는 신이십니다. 그분은 본래부터 그리고 스스로 존재와 영광과 복과 완전성이 무한하시며, 모든 것이 충족하시고 영원하시고 변함없으시고 측량할 수 없으시며 어디든지 계시고 전능하시고 만사를 아시며, 지극히 지혜로우시고 지극히 거룩하시고 지극히 의로우시고 지극히 자비로우시고 은혜로우시고 노하기를 더디 하시고 인자와 진실이 많으십니다.", references: ["요 4:24", "출 3:14", "욥 11:7∼9", "행 7:2", "딤전 4:15", "마 5:48", "창 17:1", "시 150:2", "말 3:6", "약 1:17", "왕상 8:27", "시 139:1∼13", "계 4:8", "히 4:13", "시 147:5", "롬 16:27", "시 6:3", "계 15:4", "신 32:4", "출 34:6"] },
  { number: 8, question: "하나님 한 분 외에 다른 하나님이 있습니까?", answer: "오직 한 분 하나님, 살아 계시고 참되신 하나님만 계십니다.", references: ["신 6:4", "고전 8:4, 6", "렘 10:10"] },
  { number: 9, question: "하나님의 신격(神格)에는 몇 위(位)가 계십니까?", answer: "하나님의 신격에는 성부 ․ 성자 ․ 성신 삼위가 계십니다. 이 삼위는 참되고 영원하신 한 분 하나님이시며 본질이 동일하시고 권능과 영광이 동등하십니다. 다만 위격의 속성에서 구분되십니다.", references: ["요일 5:7", "마 3:16∼17", "마 28:19", "고후 13:4", "요 10:30"] },
  { number: 10, question: "신격 안에서 삼위의 위격적 속성이 무엇입니까?", answer: "성부는 성자를 낳으시고, 성자는 성부에게서 영원히 나시며, 성신은 성부와 성자에게서 영원히 나오십니다.", references: ["히 1:5, 6, 8", "요1:14, 18", "요15:26", "갈 4:6"] },
  { number: 11, question: "성자와 성신이 성부와 동등하신 하나님이신 것이 어떻게 나타납니까?", answer: "성경은 하나님에게만 고유한 이름과 속성과 사역과 예배를 성자와 성신에게 돌려서 성자와 성신이 성부와 동등하심을 명백히 나타냅니다.", references: ["사 6:3, 5, 8", "요 12:41", "행 28:25", "요일 5:20", "행 5:3∼4", "요 1:1", "사 9:6", "요 2:24∼25", "고전 2:10∼11", "골1:16", "창 1:2", "마 28:19", "고후 13:14"] },
  { number: 12, question: "하나님의 작정(作定)이 무엇입니까?", answer: "하나님의 작정은 그분의 뜻대로 계획하신 지혜롭고 자유롭고 거룩한 작용입니다. 이로써 영원 전에 하나님께서는 자기의 영광을 위하여 시간에서 일어나는 모든 일들을 특별히 천사들과 사람들과 관련하여 불변하게 미리 정하셨습니다.", references: ["엡 1:11", "롬 11:33", "롬 9:14, 15, 18", "엡 1:4, 11", "롬 9:22-23", "시 33:11"] },
  { number: 13, question: "하나님께서 천사들과 사람들과 관련하여 특별히 작정하신 것이 무엇입니까?", answer: "하나님께서는 영원하고 불변하는 작정에 의하여, 자기의 순전한 사랑으로, 어떤 천사들을 영광에 이르도록 선택하셨고, 그리스도 안에서 어떤 사람들을 영원한 생명에 이르도록 택하시면서 그것에 이르기에 필요한 방도들을 정하셨으니, 이는 정해진 때에 드러내실 그분의 영광스러운 은혜를 찬송하게 하시기 위함입니다. 또한 그분의 주권적 능력과 (원하시는 대로 은혜를 베푸시기도 하고 거두시기도 하시는) 그분의 뜻의 측량할 수 없는 경륜을 따라 나머지 사람들을 지나치시고 그들의 죄에 대하여 수치와 진노에 처하도록 정하셨으니, 이는 그분의 공의의 영광을 찬송하게 하시기 위함입니다.", references: ["딤전 5:21", "엡 1:4-6", "살후 2:13-14", "롬 9:17, 18, 21, 22", "마 11:25-26", "딤후 2:20", "유 4", "벧전 2:8"] },
  { number: 14, question: "하나님께서 그분의 작정을 어떻게 이루십니까?", answer: "하나님께서는 그분의 무오하신 예지(豫知)와 뜻하신 자유롭고 불변하는 계획을 따라 그분의 작정을 창조와 섭리의 일로써 이루십니다.", references: ["엡 1:11", "단 4:35", "사 40:12-31"] },
  { number: 15, question: "하나님께서 창조하신 일이 무엇입니까?", answer: "하나님께서 창조하신 일은, 태초에 엿새 동안 아무것도 없는 중에서 그분의 능력 있는 말씀으로 세상과 그 안에 있는 만물을 지으신 것인데, 하나님의 보시기에 모든 것이 매우 좋았습니다.", references: ["창 1", "히 11:3", "잠 16:4", "계 4:11", "시 33:5-6"] },
  { number: 16, question: "하나님께서 천사를 어떻게 지으셨습니까?", answer: "하나님께서 모든 천사를 영으로 지으시되 불멸하고 거룩하고 지식에 뛰어나고 능력 있게 하셔서 그분의 계명을 행하고 그분의 이름을 찬송하게 하셨으나, 그들은 변할 수 있었습니다.", references: ["골 1:16", "시104:4", "마 22:30", "마 25:31", "삼하 14:17", "마 24:36", "살후 1:17", "시 103:20-21", "벧후 2:4"] },
  { number: 17, question: "하나님께서 사람을 어떻게 지으셨습니까?", answer: "하나님께서 다른 모든 피조물을 만드신 후에 사람을 남자와 여자로 지으시되 땅의 흙으로 남자의 몸을 조성하시고 남자의 갈빗대로 여자를 만드시며, 그들에게 이성적이고 불멸하는 산 영을 입히셨고, 하나님의 형상을 따라 지식과 참된 의와 거룩함으로 그들을 지으셨고, 하나님의 법이 그 마음에 기록되게 하시며 그것을 행할 능력을 주셨고 피조물을 다스리게 하셨으나, 그들은 타락할 수 있었습니다.", references: ["창 1:27", "창 2:7, 22", "욥 35:11", "전 12:7", "마 10:28", "눅 23:43", "창 1:27", "골 3:10", "엡 4:24", "롬 2:14∼15", "전 7:29", "창 1:28", "창 3:6"] },
  { number: 18, question: "하나님께서 섭리하시는 일이 무엇입니까?", answer: "하나님께서 섭리하시는 일은 자기의 모든 피조물을 가장 거룩하고 지혜롭고 능력 있게 보존하시고 통치하시는 것이며, 하나님의 영광을 위하여 그것들과 그 모든 활동을 배정(配定)하시는 것입니다.", references: ["시 145:17", "시 104:24", "사 28:2", "히 1:3", "시 103:19", "마 10:29∼31", "창 14:7", "롬 11:26", "사 63:14"] },
  { number: 19, question: "하나님께서 천사를 향하여 섭리하시는 일이 무엇입니까?", answer: "하나님께서는 섭리로써 어떤 천사들로 하여금 고의로 돌이킬 수 없이 죄와 정죄에 떨어지게 허용하시되, 하나님의 영광을 위하여 그들의 타락과 그 모든 죄를 제한하고 배정하십니다. 나머지 천사들은 거룩함과 복 가운데 세워 두시고 그 기뻐하시는 대로 그들 모두를 쓰셔서 하나님의 능력과 자비와 공의를 시행하십니다.", references: ["유 1:6", "벧후 2:4", "히 2:16", "요 8:44", "욥 1:12", "마 8:31", "딤전 5:21", "막 8:38", "히 12:22", "시 104:4", "왕하 19:35", "히 1:14"] },
  { number: 20, question: "사람이 창조받은 지위에 있을 때에 하나님께서 그에게 행하신 섭리는 무엇입니까?", answer: "사람이 창조받은 지위에 있을 때에 하나님께서 그에게 행하신 섭리는 그를 낙원에 두시고, 그것을 경작하게 하시고, 그 땅의 열매를 마음대로 먹을 자유를 그에게 주시며, 피조물을 다스릴 권세를 주시고, 돕는 배필과 혼인하게 정하셨으며, 하나님과 교제하도록 허락하셨으며, 안식일을 제정하시며, 인격적이고 완전하고 영속적인 순종을 조건으로 사람과 생명의 언약을 맺으시고 그 생명의 보증으로 생명나무를 주셨으며, 선악을 알게 하는 나무의 열매를 먹는 것을 사망의 벌로써 금하셨습니다.", references: ["창 2:8, 15, 16", "창 1:28", "창 2:18", "창 1:26-29", "창 30:8", "창 2:3", "갈 3:12", "롬 10:5", "창 2:9, 17"] },
  { number: 21, question: "사람이 처음에 하나님께 창조받은 지위에 그대로 있었습니까?", answer: "우리 시조는 의지의 자유를 받았으나 사탄의 꾐에 빠져 금하신 열매를 먹어 하나님의 계명을 위반하였고, 그리하여 창조받은 무죄 상태에서 떨어졌습니다.", references: ["창 3:6∼8", "전 7:29", "고후 11:3"] },
  { number: 22, question: "모든 사람이 그 첫 범죄 때에 타락하였습니까?", answer: "공인(公人)으로서 아담과 맺으신 언약은 아담 한 사람만이 아니라 그의 후손까지 위한 것이므로, 보통 출생법으로 아담의 후손이 된 모든 인류는 아담의 첫 범죄 때에 그의 안에서 죄를 짓고 그와 함께 타락하였습니다.", references: ["행 17:26", "창 2:16∼17", "롬 5:12∼20", "고전 15:21∼22"] },
  { number: 23, question: "타락으로 말미암아 인류는 어떤 처지에 떨어지게 되었습니까?", answer: "타락으로 말미암아 인류는 죄와 비참한 처지에 떨어지게 되었습니다.", references: ["롬 5:12", "롬 3:23"] },
  { number: 24, question: "죄가 무엇입니까?", answer: "죄는 이성 있는 피조물에게 준칙으로 주신 하나님의 율법을 조금이라도 부족하게 지키거나 그 법을 어기는 것입니다.", references: ["요일 3:4", "갈 3:10, 12"] },
  { number: 25, question: "사람이 그 타락한 처지에서 죄 되는 것은 무엇입니까?", answer: "사람이 그 타락한 처지에서 죄 되는 것은 아담의 첫 범죄의 죄책(罪責)과, 그가 창조 시에 받은 원시의(原始義)가 없는 것과, 그의 본성이 부패하여 영적으로 선한 모든 것을 전혀 바라거나 행할 수 없고 오히려 그것을 대적하며 오직 모든 악을 계속 행하려 하는 것인데, 이것이 보통 원죄(原罪)라 하는 것이고, 아울러 이 죄로 말미암아 나오는 모든 자범죄(自犯罪)입니다.", references: ["롬 5:12, 19", "롬 3:10-19", "롬 2:1-3", "롬 5:6", "롬 8:7-8", "창 6:5", "약 1:14-15", "마 15:9"] },
  { number: 26, question: "원죄가 어떻게 우리 시조에게서 그 후손들에게로 전달됩니까?", answer: "원죄는 우리 시조에게서 그 후손들에게로 보통 출생법으로 전달되어서, 그들에게서 태어나는 모든 사람이 죄악 중에 잉태되고 출생합니다.", references: ["시 51:5", "욥 14:4", "욥 15:14"] },
  { number: 27, question: "사람이 그 타락한 처지에서 비참한 것은 무엇입니까?", answer: "모든 인류는 타락함으로 말미암아 하나님과 교제가 끊어졌고 하나님의 진노와 저주 아래 있으며, 그로 말미암아 우리는 본성상 진노의 자녀이고 사탄의 종이며 이 세상과 오는 세상에서 온갖 형벌을 받아 마땅합니다.", references: ["창 3:8, 10, 24", "엡 2:2∼3", "딤후 2:26", "창 2:17", "애 3:39", "롬 6:23", "마 25:41, 46", "유 1:7"] },
  { number: 28, question: "이 세상에서 죄의 형벌이 무엇입니까?", answer: "이 세상에서 죄의 형벌은 내면적으로는 어두운 마음과 상실한 마음과 강한 유혹과 고집과 양심의 두려움과 부끄러운 욕심이 있고, 외면적으로는 우리 때문에 피조물이 당하는 하나님의 진노와 우리의 몸과 이름과 지위와 관계와 활동에 임하는 다른 모든 악이 있으며, 또한 사망이 있습니다.", references: ["엡 4:18", "롬 1:28", "살후 2:11", "롬 2:5", "사 33:14", "창 4:13", "마 27:4", "롬 1:26", "창 3:17", "신 28:15∼68", "롬 6:21, 23"] },
  { number: 29, question: "오는 세상에서 죄의 형벌이 무엇입니까?", answer: "오는 세상에서 죄의 형벌은 하나님의 즐거운 앞에서 영원히 쫓겨나는 것과 지옥 불 가운데서 몸과 영혼에 극심한 고통을 쉼 없이 받는 것입니다.", references: ["살후 1:9", "막 9:43, 44, 46, 48", "눅 16:24"] },
  { number: 30, question: "하나님께서 모든 인류를 죄와 비참한 처지에서 멸망하게 버려두셨습니까?", answer: "사람이 행위 언약이라고 부르는 첫째 언약을 위반하여 죄와 비참한 처지에 떨어졌으나 하나님께서는 모든 인류를 거기에 버려두지 아니하시고, 은혜 언약이라고 부르는 둘째 언약을 세워, 오직 사랑과 긍휼하심으로써 자기의 택하신 사람들을 거기서 건져 내어 구원의 지위에 이르게 하십니다.", references: ["살전 5:9", "갈 3:10, 12", "딛 3:4∼7", "갈 3:21", "롬 3:20∼22"] },
  { number: 31, question: "은혜 언약은 누구와 맺으신 것입니까?", answer: "은혜 언약은 둘째 아담이신 그리스도와, 또한 그분 안에서 그분의 씨인 모든 택하신 사람들과 맺으신 것입니다.", references: ["갈 3:16", "롬 5:15∼21", "사 53:10∼11"] },
  { number: 32, question: "하나님의 은혜가 둘째 언약에 어떻게 나타났습니까?", answer: "하나님의 은혜가 둘째 언약에 이렇게 나타났으니, 곧 하나님께서 중보자와 그에 의한 생명과 구원을 준비하여 죄인들에게 값없이 제시하시고, 그들로 하여금 중보자 안에 있게 하는 조건으로 믿음을 요구하시면서 그의 성신을 모든 택하신 자들에게 약속하시고 주시사 그 믿음을 다른 구원 얻는 은혜들과 더불어 그들 안에 일으키실 뿐만 아니라 그들의 믿음과 하나님을 향한 감사가 참되다는 증거로서나 그들을 구원으로 작정하신 방법으로서 모든 거룩한 순종에 이를 수 있도록 하시는 것입니다.", references: ["창 3:15", "사 42:6", "사 26:27", "요일 5:11∼12", "요 3:16", "요 1:12", "잠 1:23", "고후 4:13", "갈 5:22-23", "겔 36:27", "약 2:18, 22", "고후 5:14-15", "엡 2:10"] },
  { number: 33, question: "은혜 언약은 언제나 하나의 동일한 방법으로 시행되었습니까?", answer: "은혜 언약은 언제나 동일한 방법으로 시행된 것이 아니고, 구약 시대와 신약 시대에 다르게 시행되었습니다.", references: ["고후 3:6∼9", "히 1:1-2", "히 8:7-8"] },
  { number: 34, question: "은혜 언약이 구약 아래에서는 어떻게 시행되었습니까?", answer: "은혜 언약이 구약 아래에서는 약속, 예언, 제사, 할례, 유월절, 기타 여러 모형과 규례들로 시행되었는데, 이것은 모두 오실 그리스도를 예표(豫表)하였습니다. 그것들이 그때에는 택하신 사람들로 하여금 약속하신 메시야를 믿도록 세우는 데에 충분하였습니다. 메시야로 말미암아 그들은 죄의 완전한 용서와 영원한 구원을 얻었습니다.", references: ["롬 15:8", "행 3:20, 24", "히 10:1", "롬 4:11", "고전 5:7", "히8:9-10", "히11:13", "갈 3:7∼9, 14"] },
  { number: 35, question: "은혜 언약이 신약 아래에서는 어떻게 시행되었습니까?", answer: "신약 아래에서는 실체이신 그리스도께서 드러나셨습니다. 이 은혜 언약은 말씀의 강설과 세례와 주의 만찬이라는 성례를 집행하는 것으로 시행되었고 지금도 그러합니다. 여기에서는 은혜와 구원이 더 충만함과 증거와 효과를 가지고 모든 나라에 제시됩니다.", references: ["막 16:15", "마 28:19∼20", "고전 11:13∼25", "고후 3:6∼18", "히 8:6, 10, 11", "마 28:19"] },
  { number: 36, question: "은혜 언약의 중보자는 누구입니까?", answer: "은혜 언약의 중보자는 오직 주 예수 그리스도이십니다. 그분은 하나님의 영원하신 아들이시며 아버지와 한 본질이시고 동등하신 분으로서, 때가 찼을 때에 사람이 되셨고, 한 위에 구별되는 두 본성을 가지신 하나님이시고 사람이셨으며, 지금도 그리고 영원토록 그러하십니다.", references: ["딤전 2:5", "요1:1, 14", "요 10:30", "빌 2:6", "갈 4:4", "눅 1:35", "롬 9:5", "골 2:9", "히 7:24-25"] },
  { number: 37, question: "하나님의 아들이신 그리스도께서 어떻게 사람이 되셨습니까?", answer: "하나님의 아들이신 그리스도께서는 성신의 능력으로 잉태되어 동정녀 마리아의 몸에서 참몸과 지각 있는 영혼을 취하심으로 마리아와 동일한 본질에 속한 사람이 되셨습니다. 또한 마리아에게서 태어나셨으나 죄는 없으십니다.", references: ["요 1:14", "마 26:38", "눅 1:27, 31, 35, 42", "갈 4:4", "히 4:15", "히 7:26"] },
  { number: 38, question: "중보자는 왜 반드시 하나님이셔야 합니까?", answer: "중보자가 반드시 하나님이셔야 하는 것은 인성(人性)이 하나님의 무한한 진노와 사망의 권세 아래 떨어지지 않도록 보존하고 지키고, 그분의 고난과 순종과 기도에 가치와 효과를 주어, 하나님의 의를 만족시키고 그분의 은혜를 얻고 친백성을 값 주어 사고 그의 성신을 그들에게 주고 그들의 모든 원수를 이기고 그들을 영원한 구원에 이끌기 위함입니다.", references: ["행 2:24∼25", "롬 1:4", "롬 4:25", "히 9:14", "행 20:28", "롬 7:25-28", "롬 3:24-26", "엡 1:6", "마 3:17", "딛 2:13-14", "갈 4:6", "눅 1:68, 69, 71, 74", "히 5:8-9", "히 9:11-15"] },
  { number: 39, question: "중보자는 왜 반드시 사람이셔야 합니까?", answer: "중보자가 반드시 사람이셔야 하는 것은, 우리의 본성을 향상시키고, 율법에 순종하고, 우리의 본성에서 우리를 위하여 고난 받고 기도하며, 우리의 연약함을 체휼(體恤)하여, 우리가 양자(養子) 됨을 얻고, 위로와 은혜의 보좌에 담대히 나아감을 얻게 하시기 위함입니다.", references: ["히 2:16", "갈 4:4", "히 2:14", "히 7:24-25", "히 4:15", "갈 4:5", "히 4:16"] },
  { number: 40, question: "중보자는 왜 반드시 한 위에 하나님이시며 사람이셔야 합니까?", answer: "하나님과 사람을 화목시킬 중보자가 하나님이시면서 사람이시되 한 위에서 그리하셔야 하는 것은, 각 본성의 고유한 사역이 전인(全人)의 사역으로서 우리를 위하여 하나님에게 받으심을 얻고 또한 우리의 의지(依支)가 될 수 있기 위함입니다.", references: ["마 1:21, 23", "마 3:17", "히 9:14", "벧전 2:6"] },
  { number: 41, question: "우리의 중보자를 왜 예수라 불렀습니까?", answer: "우리의 중보자를 예수라 부른 것은, 자기 백성을 그들의 죄에서 구원하시기 때문입니다.", references: ["마 1:21"] },
  { number: 42, question: "우리의 중보자를 왜 그리스도라 불렀습니까?", answer: "우리의 중보자를 그리스도라 부른 것은, 그분이 성신으로 한량없이 기름 부음 받으셔서, 구별되게 세움 받고 모든 권위와 능력을 충만히 갖추어서 그분의 낮아지고 높아지신 두 지위에서 그분의 교회의 선지자와 제사장과 왕의 직분을 행하셨기 때문입니다.", references: ["요 3:34", "시 45:7", "요 6:27", "마 28:18∼20", "행 3:21∼22", "눅 4:19, 21", "히 5:5∼7", "히 4:14∼15", "시 2:6", "마 21:5", "사 9:6∼7", "빌 2:8∼11"] },
  { number: 43, question: "그리스도께서 선지자의 직분을 어떻게 행하십니까?", answer: "그리스도께서는 선지자로서 우리를 세우시고 구원하시는 모든 일에 관한 하나님의 모든 뜻을 그분의 성신과 말씀으로 여러 가지 경영하시는 방식을 좇아 만대의 교회에 계시하십니다.", references: ["요 1:18", "벧전 1:10∼12", "히 1:1∼2", "요 15:15", "행 20:32", "엡 4:11∼13", "요 20:31"] },
  { number: 44, question: "그리스도께서 제사장의 직분을 어떻게 행하십니까?", answer: "그리스도께서는 제사장으로서 단번에 자신을 흠 없는 제물로 하나님께 드려 자기 백성을 사죄하시고 하나님과 화목하게 하셨고 또한 그들을 위하여 항상 간구하십니다.", references: ["히 9:14, 28", "히 2:17", "히 7:25"] },
  { number: 45, question: "그리스도께서 왕의 직분을 어떻게 행하십니까?", answer: "그리스도께서는 왕으로서 자기를 위하여 한 백성을 세상에서 불러내시고 그들에게 직분과 율법과 징계수단을 주셔서 그들을 보이는 방식으로 다스리시며, 자기의 택하신 사람들에게 구원의 은혜를 주시고 그들의 순종에 상 주시고 그들의 죄를 바로잡으시고 그들의 모든 시험과 고난 중에 그들을 보존하고 붙드시고 그들의 모든 원수를 제어하시고 자기의 영광과 그들의 유익을 위하여 모든 일을 능력 있게 배정하시며, 하나님을 알지 아니하고 복음을 순종하지 아니하는 나머지 사람들을 심판하십니다.", references: ["행 15:14-16", "사 55:4-5", "창 49:10", "시 110:3", "엡 4:11-12", "고전 12:28", "사 33:22", "마 18:17-18", "고전 5:4-5", "행 5:31", "계 22:12", "계 2:10", "계 3:19", "사 63:9", "사 1:8-9", "시 2:8-9"] },
  { number: 46, question: "그리스도의 낮아지심이 무엇입니까?", answer: "그리스도의 낮아지심은 그분이 우리를 위하여 자기 영광을 비워 종의 형체를 취하심으로 잉태되고 태어나시고 사시고 죽으셨고 그 후 부활하실 때까지 그처럼 비천한 형편에서 계신 것입니다.", references: ["빌 2:6-8", "눅 1:31", "고후 8:9", "행 2:24"] },
  { number: 47, question: "그리스도께서 잉태되고 태어나셨을 때에 어떻게 낮아지셨습니까?", answer: "그리스도께서 잉태되고 태어나셨을 때에 낮아지신 것은, 영원 전부터 하나님의 아들로서 성부의 품에 계시지만 때가 차서 기꺼이 비천한 여인에게 잉태되어 사람의 아들이 되고, 그 여인에게서 태어나신 것인데, 누구보다 비천한 형편에서 그리하셨습니다.", references: ["요 1:14, 18", "갈 4:4", "롬 2:7"] },
  { number: 48, question: "그리스도께서 사시는 동안에 어떻게 낮아지셨습니까?", answer: "그리스도께서 사시는 동안에 낮아지신 것은, 율법 아래서 내려가서 율법을 온전히 지키시고, 세상의 모욕과, 사탄의 시험과, 또한 인성에 공통되거나 그분의 낮아지신 지위에 특별히 따라오는 육신의 연약함과 싸우신 것입니다.", references: ["갈 4:4", "마 5:17", "롬 5:19", "시 22:6", "히 12:2∼3", "마 4:1-12", "눅 4:13", "히 2:17-18", "히 4:15", "시 52:13∼14"] },
  { number: 49, question: "그리스도께서 죽으실 때에 어떻게 낮아지셨습니까?", answer: "그리스도께서 죽으실 때에 낮아지심은 유다에게 배반당하시고, 제자들에게 버림당하시고, 세상에게 멸시 받고 싫어버린 바 되시고, 빌라도에게 정죄당하시고, 핍박하는 자들에게 매 맞으신 것이며, 또한 사망의 공포와 흑암의 권세와 싸우고 하나님의 진노를 맛보고 감당하시면서, 자기 생명을 죄를 위한 제물로 내어놓으시고, 고통스럽고 수치스럽고 저주스러운 십자가의 죽음을 견디신 것입니다.", references: ["마 27:4", "마 26:56", "사 53:2-3", "마 27:26-50", "요 19:34", "눅 22:44", "마 27:46", "사 53:10", "빌 2:8", "히 12:2", "갈 3:13"] },
  { number: 50, question: "죽으신 이후에 그리스도의 낮아지심은 어디 있습니까?", answer: "죽으신 후에 그리스도의 낮아지심은, 장사되신 것과, 죽은 자의 상태로 계신 것과, 사흗날까지 사망의 권세 아래 계신 것인데, 달리 표현하면 음부에 내려가신 것입니다.", references: ["고전 15:3∼4", "시 16:10", "행 2:24∼27, 31", "롬 6:9", "마 12:20"] },
  { number: 51, question: "그리스도의 높아지심이 무엇입니까?", answer: "그리스도의 높아지심은, 그분이 부활하시고, 하늘에 오르시고, 아버지의 오른편에 앉으시고, 세상을 심판하러 다시 오시는 것입니다.", references: ["고전 15:4", "막 16:19", "엡 1:20", "행 1:11", "행 17:31"] },
  { number: 52, question: "그리스도께서 부활하실 때에 어떻게 높아지셨습니까?", answer: "그리스도께서 부활하실 때에 높아지심은, (죽음에 매여 있을 수 없으시므로 ) 죽음으로 썩음을 보지 않으시고, (이 생명에 속한 죽을 가능성(mortality)이나 그 밖의 일반적인 연약함을 제외하고) 본질적인 속성을 그대로 지니고 있는 바로 그 고난당하신 몸이 그분의 영혼과 참으로 연합된 채로 자기의 능력으로 사흗날에 죽은 자들로부터 다시 살아나셔서 하나님의 아들로 인정되시고 하나님의 의를 만족시키셨으며 사망과 사망 권세를 가진 마귀를 물리치시고 살아 있는 자들과 죽은 자들의 주가 되신 것입니다. 그분은 이 모든 일을 공인(公人) 곧 그의 교회의 머리로서 행하셨으니, 이는 그들을 의롭다 하시고, 은혜로 살리시고, 그들을 도와 원수들을 물리치시고, 그들로 하여금 마지막 날에 죽은 자들 가운데서 부활할 것을 확신하게 하시려는 것입니다.", references: ["행 2:24", "시 16:10", "눅 24:39", "골 1:18", "요 10:18", "롬 1:4", "롬 4:25", "히 2:14", "롬 14:9", "고전 15:21-22", "엡 1:22-23", "롬 4:25", "엡 2:56", "고전 15:25-26", "고전 15:20", "살전 4:13-18"] },
  { number: 53, question: "그리스도께서 하늘에 오르실 때에 어떻게 높아지셨습니까?", answer: "그리스도께서 하늘에 오르실 때에 높아지심은, 부활하신 후에 자주 사도들에게 나타나 대화하시면서, 하나님 나라의 일들을 그들에게 말씀해 주시고, 복음을 모든 민족에게 전하도록 명령을 내리시고, 부활하신 지 40일 후에 우리의 본성을 지니고서 우리의 머리로서 원수들에게 승리를 거두시고는, 눈으로 볼 수 있게 가장 높은 하늘로 올라가신 것입니다. 거기서 그분은 사람들을 위하여 선물을 받으시며, 우리로 하여금 위엣 것을 사랑하게 하시며, 우리를 위하여 있을 곳을 마련하시고, 세상 끝에 다시 오실 때까지 친히 거기 계실 것입니다.", references: ["행 1:2-3", "마 28:19-20", "히 6:20", "엡 4:8", "행 1:9-11", "엡 4:10", "시 68:18", "골 3:1-2", "요 14:3", "행 3:21"] },
  { number: 54, question: "그리스도께서 하나님의 오른편에 앉으실 때에 어떻게 높아지셨습니까?", answer: "그리스도께서 하나님의 오른편에 앉으실 때에 높아지심은, 신인(神人)으로서 아버지 하나님에게 최고의 사랑을 받는 데에 나아가셔서 충만한 기쁨과 영광을 얻으시고 하늘과 땅에 있는 모든 것을 다스리는 권세를 받으시고, 자기의 교회를 모으고 보호하시며, 그들의 원수를 정복하시며, 사역자들과 백성들에게 은사와 은혜를 주시며, 그들을 위하여 기도하시는 것입니다.", references: ["빌 2:9", "행 2:28", "시 16:11", "요 17:5", "엡 1:22", "벧전 3:22", "엡 4:10-12", "시 110:1", "롬 8:34"] },
  { number: 55, question: "그리스도께서 우리를 위하여 어떻게 기도하십니까?", answer: "그리스도께서는 하늘에서 우리의 본성을 지니고서 항상 아버지 앞에 나타나시며, 지상에서 보이신 순종과 희생 제사를 공로 삼고 그 공로를 모든 신자에게 적용하신 뜻을 드러내시며, 그들에게 대한 모든 고소를 변호하시며, 그들이 날마다 실패할지라도 양심의 평온함을 누리고, 은혜의 보좌로 담대히 나아가고, 그들의 인격과 봉사가 받아들여지도록 기도하십니다.", references: ["히 9:12, 24", "히 1:3", "요 3:16", "요 17:9, 20, 24", "롬 8:33-34", "롬 5:12", "요일 2:1-2", "히 4:16", "엡 1:6", "벧전 2:5"] },
  { number: 56, question: "그리스도께서 세상을 심판하러 다시 오실 때에 어떻게 높아지십니까?", answer: "그리스도께서 세상을 심판하러 다시 오실 때에 높아지심은, 악한 사람들에게 불의하게 심판받고 정죄받으신 그분이 마지막 날에 큰 권세로 다시 오시는 것인데, 그때 자기의 영광과 아버지의 영광을 온전히 드러내시고, 그의 모든 거룩한 천사들을 데리고 오시며, 호령과 천사장의 소리와 하나님의 나팔소리로 좇아 오셔서 공의로 세상을 심판하실 것입니다.", references: ["행 3:14-15", "마 24:30", "눅 9:26", "마 25:31", "살전 4:16", "행 17:31"] },
  { number: 57, question: "그리스도께서 중보 사역으로 값 주고 사신 유익들은 무엇입니까?", answer: "그리스도께서 중보 사역으로 값 주고 사신 것은, 구속(救贖)과 또한 은혜 언약의 다른 모든 유익들입니다.", references: ["히 9:12", "고후 1:20"] },
  { number: 58, question: "우리가 어떻게 그리스도의 값 주고 사신 구속(救贖)에 참여하는 자가 됩니까?", answer: "그리스도께서 값 주고 사신 유익들을 우리에게 적용함으로써 우리가 그 유익들에 참여하는 자가 되는데, 이는 특별히 성신 하나님께서 하시는 일입니다.", references: ["요 1:11-12", "딛 3:5-6"] },
  { number: 59, question: "누가 그리스도를 통하여 구속(救贖)에 참여합니까?", answer: "그리스도께서 값 주고 얻으신 구속은 그 원하시는 사람들에게 확실하게 적용되고 효력 있게 전달됩니다. 이들은 때가 이르러 성신에 의해 복음을 따라 그리스도를 믿을 수 있게 됩니다.", references: ["요 6:37, 39", "요10:15, 16", "엡 1:13-14", "롬 8:29-30", "엡 2:8", "벧전 1:2", "요 3:36", "살후 2:13"] },
  { number: 60, question: "복음을 전혀 듣지 못하여 예수 그리스도를 알지 못하던 사람들이 본성의 빛을 따라 그들의 삶으로써 구원을 얻을 수 있습니까?", answer: "복음을 전혀 듣지 못하여 예수 그리스도를 알지 못하고, 그를 믿지 아니하는 사람들은, 본성의 빛이나 그들이 믿는 종교의 법을 따라 부지런히 자기들의 생활을 세워 갈지라도 구원받을 수 없습니다. 다른 이로서는 구원받을 수 없고 오직 그리스도로만 받을 수 있는데, 그분만이 그분의 몸인 교회의 구주이십니다.", references: ["롬 10:14", "살후 1:8-9", "요 8:24", "막 16:16", "고전 1:20-25", "롬 3:7-19", "요 4:22", "롬 9:31", "빌 3:4-10", "행 4:12", "요 6:44", "요 17:9", "엡 6:23"] },
  { number: 61, question: "복음을 듣고 교회 안에서 생활하는 사람은 모두 구원받습니까?", answer: "복음을 듣고 보이는 교회 안에서 생활하는 사람이 다 구원받는 것은 아니고, 오직 보이지 않는 교회의 참된 회원만 구원받습니다.", references: ["요 12:38-40", "롬 9:6", "마 22:14", "마7:21", "롬 11:7"] },
  { number: 62, question: "보이는 교회가 무엇입니까?", answer: "보이는 교회는 이 세상의 모든 시대와 모든 장소에서 참된 믿음을 고백하는 모든 사람들과 그들의 자녀로 이루어집니다.", references: ["고전 1:2", "고전 12:13", "롬 15:9-12", "계 7:9", "시 2:8", "시 22:27-31", "시 45:17", "마 28:19-20", "사 59:21", "고전 7:14", "행 2:39", "롬 9:1-6", "창 17:7"] },
  { number: 63, question: "보이는 교회의 특권이 무엇입니까?", answer: "보이는 교회의 특권은, 하나님의 특별한 보호와 통치 아래 있고, 모든 시대에 모든 원수의 반대에 맞서 보호하시고 보존하심을 받고, 성도의 교제와 구원의 통상적인 방도들과 은혜의 제시를 누리는 것입니다. 그리스도께서는 복음 사역을 통하여 그리스도를 믿는 자마다 구원받을 것이라고 증거하시고 자기에게 오는 자는 아무도 버리지 아니한다고 하시면서 그 은혜를 보이는 교회의 모든 회원들에게 제시하십니다.", references: ["사 4:5-6", "딤전 4:10", "시 115:1-18", "사 31:4∼5", "스 12:2-4, 8, 9", "행 2:39, 42", "시 147:19-20", "롬 9:4", "엡 4:11-12", "막 16:15-16", "요 6:37"] },
  { number: 64, question: "보이지 않는 교회가 무엇입니까?", answer: "보이지 않는 교회는 머리이신 그리스도께서 과거와 현재와 미래에 걸쳐 주님 아래에 하나로 모으시는, 택하신 사람들의 총수(總數)입니다.", references: ["엡 1:10, 22, 23", "요 10:15", "요 11:52"] },
  { number: 65, question: "보이지 않는 교회의 회원들이 그리스도에 의하여 누리는 특별한 유익들이 무엇입니까?", answer: "보이지 않는 교회의 회원들은 그리스도에 의하여 은혜와 영광 중에 그분과 연합됨과 교제함을 누립니다.", references: ["요 17:21", "엡 2:5-6", "요 17:24"] },
  { number: 66, question: "택하신 사람들이 그리스도와 연합됨은 무엇입니까?", answer: "택하신 사람들이 그리스도와 연합됨은 하나님의 은혜의 사역인데, 이로써 그들은 영적으로나 신비하게, 그러나 참되고도 나뉠 수 없이 그들의 머리와 남편이신 그리스도에게 결합됩니다. 이 결합은 그들의 효력 있는 부르심에서 이루어집니다.", references: ["엡 1:22", "엡 2:6-8", "고전 6:17", "요 10:28", "엡 5:23, 30", "벧전 5:10", "고전 1:9"] },
  { number: 67, question: "효력 있는 부르심이 무엇입니까?", answer: "효력 있는 부르심은 하나님의 전능하신 능력과 은혜의 사역인데, 이로써 하나님께서 (그 택하신 사람들에게 거저 베푸시는 특별한 사랑으로, 또한 그들 안에 하나님을 움직여서 그렇게 하시도록 하는 것이 전혀 없는 상태에서 ) 그 열납하시는 때에 그분의 말씀과 성신으로 그들을 권하여 예수 그리스도에게 이끄시고, 그들의 마음을 구원 얻도록 밝히시고, 그들의 의지를 새롭게 하며 강력히 정하셔서, 그들로 하여금 (스스로는 죄로 죽었지만) 기꺼운 마음으로 하나님의 부르심에 자유로이 응답하고 그 부르심에서 제시되고 전달되는 은혜를 받아들일 수 있게 하시는 것입니다.", references: ["요 5:25", "엡 1:18-20", "딤후 5:20, 6:1-2", "요 6:44", "살후 2:13-14", "행 26:18", "고전 2:10, 12", "겔 11:19", "겔 36:26∼27", "요 6:45", "엡 2:5", "빌 2:13", "신 30:6"] },
  { number: 68, question: "택하신 사람들만 효력 있는 부르심을 받습니까?", answer: "오직 택하신 사람들만 효력 있는 부르심을 받습니다. 다른 사람들은 말씀의 사역으로 외적인 부르심을 종종 받을 수 있고, 성신의 어떤 일반적인 사역이 있을지라도, 그들에게 제시된 은혜에 대한 고의적인 태만과 경멸 때문에 그들의 불신앙 가운데 당연히 내버려져 있을 것이어서 결코 예수 그리스도에게 진정으로 오지 아니합니다.", references: ["행 13:48", "마 22:14", "마 7:22", "마 13:20-21", "히 6:4-6", "요 12:38-39", "행 28:25-27", "요 6:64-65", "시 81:11-12"] },
  { number: 69, question: "보이지 않는 교회의 회원들이 은혜 가운데서 그리스도와 교제함이 무엇입니까?", answer: "보이지 않는 교회의 회원들이 은혜 가운데서 그리스도와 교제함은 그들이 그분의 중보 사역의 덕에 참여하는 것인데, 이로써 그들이 의롭다 하심과 양자(養子)로 삼으심과 거룩하게 하심과 그밖에 이생에서 그들이 그분과 연합함을 드러내는 모든 것을 얻습니다.", references: ["롬 8:30", "엡 1:5", "고전 1:30"] },
  { number: 70, question: "의롭다 하심이 무엇입니까?", answer: "의롭다 하심은 죄인들에게 하나님께서 값없이 주시는 은혜의 행위로, 이로써 그분이 그들의 모든 죄를 용서하시고 그들을 자기 앞에서 의롭다고 인정하고 받아 주십니다. 그들 안에서 이루어진 무엇이나 그들이 행한 무엇 때문이 아니라, 오직 그리스도의 온전한 순종과 전적으로 만족게 하심 때문이고, 그 순종과 만족게 하심은 하나님께서 그들에게 전가(轉嫁)하시고 오직 믿음으로 받습니다.", references: ["롬 3:22, 24, 25", "롬 4:5", "고후 5:19, 21", "롬 3:22, 24, 25, 27, 28", "딛 3:5, 7", "엡 1:7", "롬 5:17-19", "롬 4:6∼8", "행 10:43", "갈 2:16", "빌 3:9"] },
  { number: 71, question: "의롭다 하심이 어떻게 하나님의 값없이 주시는 은혜의 행위입니까?", answer: "그리스도께서 의롭다 하심을 받는 이들을 위해 자기의 순종과 죽음으로써 하나님의 의를 적절하고 참되고 온전히 만족시키셨지만, 하나님께서 이들에게 요구하셨을 의의 만족을 보증인에게서 받으시되, 자기 아들을 이 보증인으로 주셔서, 그분의 의를 이들에게 전가(轉嫁)하시고, 이들을 의롭다 하시는 일에 믿음 외에는 아무 것도 요구하지 않으셨으며, 게다가 이 믿음도 그분의 선물이므로, 그들을 의롭다 하심은 그들에게 값없이 주시는 은혜입니다.", references: ["롬 5:8-10, 11", "딤전 2:5-6", "히 10:10", "마 20:28", "단 9:24:26", "사 53:4-6, 10-12", "히 7:22", "롬 8:22", "벧전 1:18-19", "고후 5:21", "롬 3:24-25", "엡 2:8, 1:7"] },
  { number: 72, question: "의롭다 하심을 얻는 믿음은 무엇입니까?", answer: "의롭다 하심을 얻는 믿음은 성신과 말씀으로써 죄인의 마음에 역사하신 구원의 은혜인데, 이로써 죄인이 자기의 죄와 비참함을 깨닫고 스스로나 다른 피조물로써는 자기의 상실된 형편에서 회복될 수 없음을 깨달아서, 복음의 약속의 진리에 동의할 뿐만 아니라, 그리스도와 그분의 의를 받고 의지합니다. 복음은 죄 사함을 얻고, 하나님 앞에서 그를 의롭다고 인정하여 받아 주심을 얻도록 그리스도와 그분의 의를 제시합니다.", references: ["히 10:39", "고후 4:13", "고전 12:3, 9", "엡 1:17-19", "롬 10:14, 17", "살후 2:13", "요 16:8-9", "행 16:30", "행 2:37", "엡 2:1", "행 4:12", "롬 7:9", "롬 10:8-10", "엡 1:13", "갈 2:15-16", "행 10:43", "행 16:31", "빌 3:9", "행 15:11"] },
  { number: 73, question: "믿음이 어떻게 하나님 앞에서 죄인을 의롭다 합니까?", answer: "믿음이 하나님 앞에서 죄인을 의롭다 하는 것은, 믿음에 언제나 동반되는 다른 은혜들이나 믿음의 열매인 선행 때문이 아닙니다. 또한 마치 믿음의 은혜나 믿음의 무슨 행위가 그에게 전가(轉嫁)되어 그가 의롭다 하심을 얻는 것이 아니고, 오직 믿음이 그리스도와 그분의 의를 받고 적용하는 수단이기 때문입니다.", references: ["갈 3:2", "롬 3:28", "롬 4:5", "롬 10:10", "요 1:12", "빌 3:9", "갈 2:16"] },
  { number: 74, question: "양자(養子)로 삼으심이 무엇입니까?", answer: "양자로 삼으심은 하나님께서 그의 독생자 예수 그리스도 안에서 또한 그를 위하여 값없이 주시는 은혜의 행위이고, 이로써 의롭다 하심을 받은 모든 사람은 하나님의 자녀의 수에 들게 되고, 하나님의 이름을 자기들 위에 갖고, 그의 아들의 성신을 받고, 하나님께서 아버지로서 베푸시는 보호와 경영 아래 있고, 하나님의 자녀들의 모든 자유와 특권을 허락받고, 모든 약속의 상속자가 되고, 영광 가운데 그리스도와 함께 공동 상속자가 됩니다.", references: ["요일 3:1", "엡 1:5", "갈 4:4-5", "요 1:2", "고후 6:18", "계 3:12", "갈 4:6", "시 103:13", "잠 14:26", "마 6:32", "히 6:12", "롬 8:17"] },
  { number: 75, question: "거룩하게 하심이 무엇입니까?", answer: "거룩하게 하심은 하나님께서 값없이 주시는 은혜의 사역이고, 이로써 하나님께서 창세전에 거룩하게 하려고 택하신 사람들은, 때가 되어 그리스도의 죽음과 부활을 그들에게 적용하시는 하나님의 성신의 강력한 역사를 통하여, 그들의 전인(全人)에서 하나님의 형상을 좇아 새롭게 되고, 생명에 이르는 회개를 비롯한 다른 모든 구원의 은혜들의 씨가 그 마음에 심기고, 그 은혜들이 활발해지고 많아지고 강하게 되면서 그들은 점점 더 죄에 대하여 죽고 생명의 새로움에 대하여 살아납니다.", references: ["엡 1:4", "고전 6:11", "살후 2:13", "롬 6:4-6", "엡 4:23-24", "행 11:18", "요일 3:9", "유 20", "히 6:11-12", "엡 3:16, 19", "골 1:10∼11", "롬 6:4, 6", "갈 5:24"] },
  { number: 76, question: "생명에 이르는 회개가 무엇입니까?", answer: "생명에 이르는 회개는 하나님의 성신과 말씀에 의해 죄인의 마음에 일어난 구원의 은혜이고, 이로써 그는 자기 죄의 위험과 또한 그 누추함과 가증함을 보고 깨닫고, 하나님께서 뉘우치는 자들에게 그리스도 안에서 베푸시는 자비하심을 알아서, 자기 죄를 슬퍼하고 미워하여 그 모든 죄로부터 돌이켜 하나님에게로 향하며 새로운 순종의 모든 길에서 하나님과 늘 동행할 뜻을 품고 거기에 힘씁니다.", references: ["행 11:18, 20-21", "슥 12:10", "행 2:37", "딤후 2:25", "눅 24:47", "겔 18:30, 32", "눅 15:17-18", "호 2:6-7", "겔 36:31", "사 30:22", "눅 22:61-62", "슥 12:10", "마 26:75", "고후 7:11", "행 2:37", "렘 31:18-19", "시 130:3-7", "욜 2:12-13", "행 26:18", "겔 14:6", "왕상 8:47-48", "시 119:6, 59, 128", "눅 1:6", "롬 6:17", "롬 6:17-18", "눅 19:8", "왕하 23:25"] },
  { number: 77, question: "의롭다 하심과 거룩하게 하심은 어떻게 다릅니까?", answer: "거룩하게 하심과 의롭다 하심은 불가분리하게 연결되어 있지만, 하나님께서 의롭다 하심에서는 그리스도의 의를 전가(轉嫁)하시는 반면에 거룩하게 하심에서는 그분의 성신이 은혜를 주입하여 그 은혜를 발휘할 수 있게 하시며, 의롭다 하심에서는 죄가 용서받는 반면에 거룩하게 하심에서는 죄가 정복되며, 의롭다 하심은 모든 신자를 하나님의 보복하시는 진노에서 똑같이 자유롭게 하되 이생에서 완전히 자유롭게 하여 결코 정죄에 떨어지지 않게 하시는 반면에 거룩하게 하심은 모든 신자에게 결코 똑같지 않고 이생에서 누구에게서도 완전하지 않으며 완전을 향하여 자라 가는 점에서 서로 다릅니다.", references: ["고전 6:11", "고전 1:30", "롬 4:6, 8", "겔 36:27", "롬 3:24-25", "롬 6:6, 14", "롬 8:33-34", "요일 2:12∼14", "히 5:12-14", "요일 1:8, 10", "고후 7:1", "빌 3:12-14"] },
  { number: 78, question: "거룩하게 하심이 신자 안에서 불완전한 것은 어디서 생깁니까?", answer: "거룩하게 하심이 신자 안에서 불완전한 것은 그들의 모든 부분에 내주하는 죄의 잔재에서, 성신을 대적하는 육신의 끊임없는 욕망에서 생기는데, 이로써 그들은 자주 시험에 넘어지고, 많은 죄에 떨어지고, 온갖 신령한 봉사에 방해받고, 그들의 가장 뛰어난 행위도 하나님 보시기에 불완전하고 더럽습니다.", references: ["롬 7:18, 23", "막 14:66-72", "갈 2:11-12", "히 12:1", "사 64:6", "출 28:38"] },
  { number: 79, question: "참된 신자가 그들의 불완전함과 그들을 덮치는 많은 시험과 죄 때문에 은혜의 상태에서 떨어질 수 있습니까?", answer: "참된 신자들은 하나님의 변할 수 없는 사랑과 견인을 주시는 그분의 작정과 언약과 그들이 그리스도와 나뉠 수 없이 연합됨과 그들을 위한 그리스도의 지속적인 간구와 그들 안에 거하는 성신과 하나님의 씨 때문에 은혜의 상태에서 완전히 최종적으로 떨어지는 일이 없고, 하나님의 능력으로 지키심을 받고 믿음으로 말미암아 구원에 이릅니다.", references: ["렘 31:3", "딤후 3:9", "히 13:20", "삼하 23:5", "고전 1:8-9", "히 7:25", "눅 22:32", "요 3:9", "요일 2:27", "렘 32:40", "요 10:28", "벧전 1:5"] },
  { number: 80, question: "참된 신자는 자기가 은혜의 상태에 있으며 그 가운데서 견인하여 구원에 이를 것을 틀림없이 확신할 수 있습니까?", answer: "그리스도를 참되게 믿고 그분 앞에서 모든 선한 양심으로 행하려고 힘쓰는 사람들은 비상한 계시 없이도 하나님의 약속의 진리 위에 굳게 선 믿음으로 말미암아, 또한 자기들 안에서 생명이 약속되어 있는 은혜들을 확인할 수 있게 하시고 그들의 영과 더불어 그들이 하나님의 자녀인 것을 증거하시는 성신으로 말미암아, 그들이 은혜의 상태에 있으며 그 가운데서 견인하여 구원에 이를 것을 틀림없이 확신할 수 있습니다.", references: ["요일 2:3", "고전 2:12", "요일 3:14, 18, 19, 21, 24", "요일 4:13, 16", "요일 5:11-13", "롬 8:16"] },
  { number: 81, question: "참된 신자는 누구나 자기가 지금 은혜의 상태에 있고 장차 구원받을 것을 언제든지 확신합니까?", answer: "은혜와 구원에 대한 확신이 믿음의 본질에 속하지 아니하므로, 참된 신자는 그 확신을 얻기까지 오래 기다려야 할 수 있고, 그 확신을 누린 후에도 다양한 언짢음과 죄와 시험과 버림당한 상태로 말미암아 확신이 약하게 되고 중단될 수도 있지만, 하나님의 성신께서 임재하셔서 도우시는 까닭에 완전한 절망에 빠지는 일은 없습니다.", references: ["엡 1:13", "사 50:10", "시 88:1-18", "시 77:1-12", "갈 5:2, 3, 6", "시 51:8, 12", "시 22:1", "요일 3:9", "욥 13:15", "시 73:15, 23", "사 54:7∼10"] },
  { number: 82, question: "보이지 않는 교회의 회원들이 영광 중에 그리스도와 교제함은 무엇입니까?", answer: "보이지 않는 교회의 회원들이 영광 중에 그리스도와 교제함은 이생에도 있고, 죽은 즉시로 누리고, 마침내 부활과 심판 날에 완전해집니다.", references: ["고후 3:18", "눅 23:43", "살전 4:17"] },
  { number: 83, question: "보이지 않는 교회의 회원들이 이생에서 영광 중에 그리스도와 교제함은 무엇입니까?", answer: "보이지 않는 교회의 회원들은 그들의 머리이신 그리스도의 지체들이므로 이생에서 그리스도와 더불어 영광의 첫 열매들을 받아 가지고서 그리스도 안에서 그분이 충만히 소유하시는 그 영광에 참여하며, 그 보증으로서 하나님의 사랑을 깨달음과 양심의 평안과 성신 안에 있는 즐거움과 영광의 소망을 누립니다. 반면에 하나님의 보복하시는 진노를 깨달음과 양심의 공포와 장차 올 심판에 대한 두려움이 악한 자들에게 있는데 이것들은 그들이 죽은 후에 당할 고통의 시작입니다.", references: ["엡 1:13", "사 50:10", "시 88:1-8", "시 77:1-12", "전 12:13-14", "마 27:4", "히 10:27", "롬 2:9", "막 9:44"] },
  { number: 84, question: "모든 사람이 죽어야 합니까?", answer: "사망은 죄의 삯으로 닥치는 것인데, 모든 사람이 범죄하였으므로 한 번 죽는 것이 모든 사람에게 정하신 바가 되었습니다.", references: ["롬 6:23", "히 9:27", "롬 5:12"] },
  { number: 85, question: "사망이 죄의 삯이라면, 의인은 그의 모든 죄를 그리스도 안에서 용서받았는데 왜 사망에서 건짐 받지 못합니까?", answer: "의인은 마지막 날에 사망에서 건짐 받을 것이고, 심지어 죽을 때에도 사망의 쏘는 것과 저주에서 건짐 받습니다. 그래서 그들이 비록 죽을지라도 그것은 하나님의 사랑에서 나온 것이니, 죄와 비참함으로부터 완전히 그들을 자유롭게 하시고, 그때 영광 중에 그리스도와 더욱 교제에 들어갈 수 있게 하시는 것입니다.", references: ["고전 15:26, 55-57", "히 2:15", "사 57:1-2", "왕하 22:20", "눅 16:25", "계 14:13", "고후 5:1-8", "엡 5:27", "눅 23:43", "빌 1:23"] },
  { number: 86, question: "보이지 않는 교회의 회원들이 죽은 후에 즉시 영광 중에 그리스도와 교제함은 무엇입니까?", answer: "보이지 않는 교회의 회원들이 죽은 후에 즉시 영광 중에 그리스도와 교제함은, 그들의 영혼이 그때 온전히 거룩함에 이르게 되고 지극히 높은 하늘로 영접되어 거기서 빛과 영광 중에 하나님의 얼굴을 뵈면서 그들의 몸의 충만한 구속(救贖)을 기다리는 것인데, 그들의 몸은 죽어서도 그리스도와 연합되어 있고 마지막 날에 그들의 영혼과 다시 결합될 때까지 마치 침상에 있는 것처럼 무덤에서 쉽니다. 그러나 악인의 영혼은 죽을 때에 지옥에 던져져서 고통과 완전한 흑암 중에 있고, 그들의 몸은 저 큰 날에 부활하여 심판받을 때까지 마치 감옥에 갇힌 것처럼 무덤에 머물러 있습니다.", references: ["히 12:23", "고후 5:1, 6, 8", "빌 1:23", "행 3:21", "행 4:10", "요일 3:2", "고전 13:12", "롬 8:23", "시 16:9", "살전 4:14", "사 57:2", "욥 19:26-27", "눅 16:23∼24", "행 1:25", "유1:6, 7"] },
  { number: 87, question: "부활에 관하여 우리가 믿어야 할 것이 무엇입니까?", answer: "마지막 날에 의인들이나 불의한 자들 모두가 죽음에서 부활하게 될 것이며, 그때 살아 있는 자들은 순식간에 변화할 것이고, 그때 무덤에 놓인 죽은 자들의 몸은 그들의 영혼과 영원히 다시 결합되어 그리스도의 능력으로 일으킴 받게 되는 것을 우리는 믿어야 합니다. 의인들의 몸은 그리스도의 영에 의하여 그들의 머리이신 그리스도의 부활 덕분에 능력 가운데 일으킴 받아 신령하고 썩지 않고 그분의 영광스러운 몸과 같이 될 것이고, 악인들의 몸은 진노하신 심판장이신 그리스도에 의하여 부끄러 가운데 일으킴 받을 것입니다.", references: ["행 24:15", "고전 15:51-53", "살전 3:15-17", "요 5:28-29", "고전 15:21-23, 42-44", "빌 3:21", "요 5:27-29", "마 25:33"] },
  { number: 88, question: "부활 이후에 즉시로 따라오는 일이 무엇입니까?", answer: "부활 이후에 즉시로 천사들과 사람들에 대한 일반적이고 최종적인 심판이 따라올 것인데, 그 날과 그 시간에 관하여는 아무도 알지 못하므로 모두 깨어 기도하고 주의 오심을 늘 준비할 것입니다.", references: ["마 16:27", "벧후 2:4", "계 20:11-13", "마 24:36, 42, 44", "눅 21:35-36"] },
  { number: 89, question: "심판 날에 악인들에게 어떤 일이 이루어집니까?", answer: "심판 날에 악인들은 그리스도의 왼편에 놓이게 되고, 분명한 증거와 그들의 양심의 철저한 가책 위에서 그들에게 두렵고 공의로운 정죄가 선고될 것이고, 그로써 그들은 하나님의 은혜로운 임재와, 그리스도와 그분의 성도들과 그분의 모든 거룩한 천사들과의 영광스러운 교제에서 쫓겨나 지옥에 던져져서 몸과 영혼이 마귀와 그의 사자들과 더불어 말할 수 없는 고통으로 형벌받게 될 것입니다.", references: ["마 25:33", "롬 2:15-16", "마 25:41-43", "눅 16:26", "살후 1:8-9"] },
  { number: 90, question: "심판 날에 의인에게 어떤 일이 이루어집니까?", answer: "심판 날에 의인들은 구름 가운데서 그리스도께로 올리어 그분의 오른편에 놓이게 되고, 거기서 공개적으로 인정과 사면을 받아 그리스도와 함께 버림받은 천사들과 사람들을 심판하게 되고, 하늘로 영접 받아서 거기서 모든 죄와 비참함에서 완전히 그리고 영원히 자유롭게 되며, 지각에 넘치는 즐거움이 충만하고 몸과 영혼이 완전히 거룩하고 복된 상태에 이르고, 셀 수 없이 많은 성도들과 거룩한 천사들과 함께 하고, 특별히 성부 하나님과 우리 주 예수 그리스도와 성신을 즉시 뵈옵고 영원토록 즐거워하게 됩니다. 바로 이것이 보이지 않는 교회의 회원들이 부활과 심판 날에 영광 중에 그리스도와 함께 누리게 될 완전하고 충만한 교제입니다.", references: ["살전 4:17", "마 25:33", "마 10:32", "고전 6:2-3", "마 25:34, 46", "엡 5:27", "계 14:13", "시 16:11", "히 12:22-23", "요일 3:2", "고전 13:12", "살전 4:17-18"] },
  { number: 91, question: "하나님께서 사람에게 요구하시는 본분이 무엇입니까?", answer: "하나님께서 사람에게 요구하시는 본분은 하나님께서 계시하신 뜻을 순종하는 것입니다.", references: ["롬 12:1-2", "미 6:8", "삼상 15:22"] },
  { number: 92, question: "하나님께서 맨 처음에 사람에게 순종의 준칙으로서 계시하신 것이 무엇입니까?", answer: "하나님께서 죄 없는 상태에서 아담에게 그리고 아담 안에서 모든 인류에게 계시하신 순종의 준칙으로는 선악을 알게 하는 나무의 과일을 먹지 말라는 특별한 명령 외에 도덕의 법칙이 있습니다.", references: ["창 1:26-27", "롬 2:14-15", "롬 10:15", "창 2:17"] },
  { number: 93, question: "도덕의 법칙이 무엇입니까?", answer: "도덕의 법칙은 인류에게 하나님의 뜻을 선언한 것인데, 모든 사람이 전인(全人)의 형질(形質)과 기질(氣質) 곧 몸과 영혼으로, 하나님과 사람을 향하여 거룩함과 의로움의 모든 본분을 행할 때에 하나님의 뜻을 인격적이고 완전하고 항구적으로 따르고 순종하도록 명령하고 구속(拘束)합니다. 그것을 행하면 생명을 주리라 약속하고 그것을 위반하면 죽을 것이라 경고합니다.", references: ["신 5:1-3, 31, 33", "눅 10:26-27", "갈 3:10", "살전 5:23", "눅 1:75", "행 24:16", "롬 10:5", "갈 3:10, 12"] },
  { number: 94, question: "타락 이후에 도덕의 법칙은 사람에게 무슨 용도가 있습니까?", answer: "타락 이후에는 아무도 도덕의 법칙으로 의로움과 생명에 도달할 수 없지만, 그것의 중대한 용도가 모든 사람에게 공통으로 있고, 또한 곧 거듭난 사람이나 거듭나지 못한 사람에게 독특하게 있습니다.", references: ["롬 8:3", "갈 2:16", "딤전 1:8"] },
  { number: 95, question: "모든 사람에게 공통되는 도덕의 법칙의 용도가 무엇입니까?", answer: "도덕의 법칙은 모든 사람에게 하나님의 거룩하신 본성과 뜻, 그들로 준행하도록 얽매는 그들의 본분에 관하여 알려주고, 그들이 그것을 지킬 수 없고 그들의 본성과 마음과 삶이 죄악으로 오염되었음을 깨닫게 하고, 그들이 자기의 죄와 비참함을 느껴서 겸손하게 하고, 그리하여 그리스도와 그분의 완전한 순종이 필요함을 더욱 분명히 볼 수 있게 돕는 용도가 있습니다.", references: ["레 11:44-45", "레 20:7-8", "롬 7:12", "미 6:8", "약 2:10-11", "시 19:11-12", "롬 3:20", "롬 7:7", "롬 3:9, 23", "갈 3:21-22", "롬 10:4"] },
  { number: 96, question: "거듭나지 못한 사람들에게 도덕의 법칙의 특별한 용도가 무엇입니까?", answer: "도덕의 법칙은 거듭나지 못한 사람들의 양심을 일깨워 다가오는 진노에서 피하게 하고, 그들을 그리스도에게로 이끌며, 만일 그들이 죄의 상태와 죄의 길을 고집할 때에 그들로 핑계할 수 없게 하고, 저주 아래 있게 하는 용도가 있습니다.", references: ["딤전 1:9-10", "갈 3:24", "롬 1:20", "롬 2:15", "갈 3:10"] },
  { number: 97, question: "거듭난 사람들에게 도덕의 법칙의 특별한 용도가 무엇입니까?", answer: "거듭나서 그리스도를 믿는 사람들은 행위 언약으로서의 도덕의 법칙에서 건짐 받으므로 그 법칙으로 의롭다 하심이나 정죄를 받는 것은 아니지만, 모든 사람에게 공통된 도덕의 법칙의 일반적 용도들 외에 특별한 용도가 있으니, 곧 그 법칙을 이루셔서 그들 대신에 그들의 유익을 위하여 그것의 저주를 견디신 그리스도에게 그들이 얼마나 매여 있는지를 보여 주고, 그리하여 그들로 하여금 더욱 감사의 심정에 이르게 하고, 그들이 순종할 준칙으로서 그 법칙을 따르는 일에 더욱 마음을 기울여 감사를 표시하게 하는 용도가 있습니다.", references: ["롬 6:14, 7:4, 6", "갈 4:4-5", "롬 3:20", "갈 5:23", "롬 8:1", "롬 7:24-25", "갈 3:13-14", "롬 8:3-4", "눅 1:68-69, 74-75", "골 1:12-14", "롬 7:22", "롬 12:2", "딛 2:11-14"] },
  { number: 98, question: "도덕의 법칙은 어디에 총괄되어 나타났습니까?", answer: "도덕의 법칙은 십계명에 총괄되어 나타났는데, 이 십계명은 하나님께서 친히 시내 산에서 음성으로 반포하시고 두 돌비에 쓰셨으며, 출애굽기 20장에 기록되어 있습니다. 처음 네 계명은 하나님에 대한 우리의 본분이고 다른 여섯 계명은 사람에 대한 우리의 본분입니다.", references: ["신 10:4", "출 34:1-4", "마 22:37-40"] },
  { number: 99, question: "십계명을 올바르게 깨닫기 위하여 지켜야 할 준칙이 무엇입니까?", answer: "십계명을 올바르게 깨닫기 위해서는 다음의 준칙을 지켜야 합니다.", references: ["시 19:7", "약 2:10", "마 5:21-48", "롬 7:14", "신 6:5", "마 22:37-39", "골 3:5", "암 8:5", "잠 1:19", "딤전 6:10", "사 58:13", "신 6:13", "마 4:9-10", "마15:4-6", "마5:21-24", "엡 4:28", "출 20:12", "잠 30:17", "렘 18:7-8", "출 20:7", "출 15:1, 4, 5", "욥 13:7-8", "롬 3:8", "욥 36:21", "히 11:25", "신 4:8-9", "마12:7", "마5:21-22, 27-28", "마15:4-6", "히 10:24-25", "살전 5:22", "유 1:23", "갈 5:26", "골 3:21", "출 20:10", "레19:17", "창 18:19", "수 24:15", "신 6:6-8", "고후 1:24", "딤전 5:22", "엡 5:11", "시 24:4-5"] },
  { number: 100, question: "십계명에서 우리가 살펴야 할 특별한 것들이 무엇입니까?", answer: "십계명에서 우리가 살펴야 할 특별한 것들은, 머리말과 계명들의 내용, 그리고 몇몇 계명의 경우에 그것들을 더욱 힘쓰도록 거기에 붙은 이유들입니다.", references: [] },
  { number: 101, question: "십계명의 머리말이 무엇입니까?", answer: "십계명의 머리말은 “나는 너를 애굽 땅 종 되었던 집에서 인도하여 낸 너의 하나님 여호와로라” 하신 것인데, 이 머리말에서 하나님은 여호와 곧 영원하시고 불변하시고 전능하신 하나님이시고, 스스로 존재를 가지시며, 자기의 모든 말씀과 사역에 존재를 주시는 분으로서 자기의 주권을 나타내셨습니다. 또한 하나님은 언약의 하나님으로서 옛적 이스라엘과 언약을 맺으셨던 것처럼 자기의 모든 백성과도 맺으셨으니, 이스라엘을 애굽의 종살이에서 이끌어 내신 것처럼, 우리를 우리의 영적 속박 상태에서 건져 주셨습니다. 그러므로 우리는 하나님을 오직 우리 하나님으로 모시고 그분의 모든 계명을 지켜야 합니다.", references: ["출 20:2", "사 44:6", "출 3:14", "출6:3", "행 17:24, 28", "창 17:7", "롬 3:29", "눅 1:74-75", "벧전 1:15-18", "레 18:30", "레 19:37"] },
  { number: 102, question: "하나님에 대한 우리의 본분인 네 계명의 강령(綱領)은 무엇입니까?", answer: "하나님에 대한 우리의 본분인 네 계명의 강령은 우리의 마음을 다하고 목숨을 다하고 힘을 다하고 뜻을 다하여 주 우리 하나님을 사랑하는 것입니다.", references: ["눅 10:27"] },
  { number: 103, question: "제1계명이 무엇입니까?", answer: "제1계명은 “너는 나 외에는 다른 신들을 네게 있게 말지니라” 하신 것입니다.", references: ["출 20:3"] },
  { number: 104, question: "제1계명이 명하는 것은 무엇입니까?", answer: "제1계명이 명하는 것은, 하나님께서 유일하고 참되신 하나님이시고 우리의 하나님이심을 알고 인정하며, 그에 합당하게 하나님을 경배하고 영화롭게 하라는 것입니다. 그러므로 우리는 하나님을 생각하고, 묵상하고, 기억하고, 높이고, 공경하고, 숭배하고, 택하고, 사랑하고, 사모하고, 경외하며, 하나님을 믿으며, 하나님을 의지하고, 소망하고, 기뻐하고, 즐거워하며, 하나님을 위하여 열심을 품으며, 하나님의 이름을 부르고, 모든 찬송과 감사를 드리며, 전인(全人)으로서 하나님께 모든 순종과 순복을 드리며, 하나님을 기쁘시게 하려고 모든 일에 주의하고, 무슨 일이든 하나님께서 미워하시는 일을 슬퍼하고, 겸손히 하나님과 동행해야 합니다.", references: ["대상 28:9", "신 26:17", "사 43:10", "렘 4:22", "시 95:6-7", "마 4:10", "시 29:2", "말 3:16", "시 63:6", "전 12:1", "시 71:19", "말 1:6", "사 45:23", "수 24:15, 22", "신 6:5", "시 73:25", "사 8:13", "출 14:31", "사 26:4", "시 130:7", "시 37:4", "시32:11", "롬 12:11", "민 25:11", "빌 4:6", "렘 7:23", "약 4:7", "요일 3:22", "렘 31:18", "시 119:136", "미 6:8"] },
  { number: 105, question: "제1계명이 금하는 죄는 무엇입니까?", answer: "제1계명이 금하는 죄는 하나님을 부인하거나 모시지 않는 무신론과, 한 분 하나님 외에 다른 신들을 모시든지 섬기거나 참되신 하나님과 더불어 혹은 참되신 하나님 대신에 다른 무엇을 모시든지 섬기는 우상 숭배와, 하나님을 하나님으로 또한 우리 하나님으로 모시고 인정하지 않는 것과, 이 계명에서 명하는 대로 하나님께 마땅한 의무를 빠뜨리거나 소홀히 하는 것과, 하나님에 대한 무지나 망각이나 오해나 거짓된 견해나 부당하고 악한 생각과, 하나님의 비밀을 뻔뻔한 태도로 시시콜콜 캐는 것과, 하나님에 대한 모든 신성모독이나 미움과, 자기 사랑이나 자기를 추구하는 것이나 그 밖에 우리의 지성과 의지나 감정을 다른 사물에 과도하고 무절제하게 쏟아서 그 모든 것을 전부로나 부분적으로 하나님으로부터 빼앗는 것과, 헛되고 경솔한 믿음이나 불신앙이나 이단이나 그릇된 믿음이나 의심이나 좌절이나 완고함이나 심판 아래 있어도 무감각한 것이나 마음이 강퍅한 것이나 교만이나 주제 넘는 태도나 육적인 방심이나 하나님을 시험하는 것과, 불법적인 수단을 사용하는 것이나 비록 합법적일지라도 수단 자체를 의지하는 것과, 육적 쾌락이나 향락과, 부패하고 맹목적이고 분별없는 열심과, 하나님의 일에 뜨뜻미지근함이나 무감각함과, 스스로 하나님을 떠나 배도(背道)하는 것과, 성인(聖人)이나 천사나 다른 어떤 피조물에게 기도하거나 무릇 그것들에게 예배하는 것과, 마귀와 약속하거나 그에게 묻거나 그의 제안에 귀가 솔깃한 것과, 사람을 우리의 믿음과 양심의 주인으로 삼는 것과, 하나님과 그분의 명령을 가볍게 여기고 멸시하는 것과, 그분의 성신을 거역하고 근심케 하거나, 하나님의 경영하심에 불만을 품고 참지 못하거나, 하나님께서 우리에게 내리신 재앙을 어리석게 원망하는 것과, 우리가 존재하고 소유하고 행할 수 있는 모든 선에 관하여 운명이나 우상이나 우리 자신이나 다른 어떤 피조물을 칭송하는 것입니다.", references: ["시 14:1", "엡 2:12", "엡 2:27-28", "살전 1:9", "시81:2", "사 43:22-24", "렘 4:22", "호 4:1, 6", "렘 2:32", "행 17:23, 29", "사 40:18", "신 29:29", "딛1:16", "히 12:16", "롬 1:30", "딤후 3:2", "빌 2:21", "요일 2:15-16", "삼상 2:29", "골 3:35", "요일 4:1", "히 3:12", "갈 5:20", "딛 3:10", "행 16:9", "시 78:22", "창 4:13", "렘 5:3", "사 42:25", "롬 2:5", "렘 13:15", "시 19:13", "스 1:12", "마 4:7", "롬 3:8", "렘 17:5", "딤후 3:4", "갈 4:17", "요 16:2", "롬 10:2", "눅 9:54-55", "계 3:16", "계 3:1", "겔 14:5", "사 1:4-5", "롬 10:13-14", "요 4:12", "행 10:25-26", "계 19:10", "마 4:10", "골 2:18", "롬 1:25", "레 20:6", "삼상 28:7, 11", "대상 10:13-14", "행 5:3", "고후1:24", "마 23:9", "신 32:15", "삼하 12:9", "잠 13:13", "행 7:51", "엡 4:30", "시 78:2-3, 13-15, 22", "욥 1:22", "삼상 6:7-9", "단 5:23", "신 8:17", "단 4:30", "히 1:16"] },
  { number: 106, question: "‘나 외에는’이라는 표현이 제1계명에서 특별히 가르치는 것은 무엇입니까?", answer: "‘나 외에는’ 곧 ‘내 앞에서’라는 표현이 제1계명에서 우리에게 가르치는 것은, 모든 것을 보시는 하나님께서 다른 어떤 신을 모시는 죄를 특별히 주목하시고 그 죄를 매우 싫어하신다는 것입니다. 이는 이 죄를 짓지 않도록 막고 이 죄를 매우 뻔뻔한 도발로서 심각하게 제시할 뿐만 아니라 우리가 하나님을 섬기는 모든 일을 그분의 눈앞에서 행하도록 설복하는 논증입니다.", references: ["겔 8:5-18", "시 44:20-21", "대상 28:9"] },
  { number: 107, question: "제2계명이 무엇입니까?", answer: "제2계명은 “너를 위하여 새긴 우상을 만들지 말고 또 위로 하늘에 있는 것이나 아래로 땅에 있는 것이나 땅 아래 물속에 있는 것의 아무 형상이든지 만들지 말며 그것들에게 절하지 말며 그것들을 섬기지 말라. 나 여호와 너의 하나님은 질투하는 하나님인즉 나를 미워하는 자의 죄를 갚되 아비로부터 아들에게로 삼사 대까지 이르게 하거니와 나를 사랑하고 내 계명을 지키는 자에게는 천 대까지 은혜를 베푸느니라” 하신 것입니다.", references: ["출 20:4-6"] },
  { number: 108, question: "제2계명이 명하는 본분은 무엇입니까?", answer: "제2계명이 명하는 본분은, 하나님께서 그분의 말씀에서 제정하여 주신 그 모든 경건한 예배와 규례, 곧 그리스도의 이름으로 드리는 기도와 감사, 말씀을 낭독하고 설교하고 듣는 것, 성례를 실시하고 받는 것, 교정(敎政)과 권징(勸懲), 그 사역과 유지, 종교적 금식, 하나님의 이름으로 맹세하고 하나님께 서약하는 것 등을 받아들이고 행하며 순전하고 온전하게 지키라는 것입니다. 그처럼 모든 거짓된 예배를 거부하고 미워하고 반대하며, 각자의 지위와 소명에 따라서 거짓 예배와 우상 숭배 기념물을 제거하라는 것입니다.", references: ["신 32:46-47", "마 28:20", "행 2:42", "딤전 6:13-14", "빌 4:6", "엡 5:20", "신 17:18-19", "행 15:21", "딤후 4:2", "약1:21-22", "행 10:33", "마 28:9", "고전 11:23-30", "마 18:15-17", "마 16:19", "고전 5:1-13", "고전 12:28", "엡 4:11-12", "딤전 5:17-18", "고전 9:7-15", "요엘 2:12-13", "고전 7:5", "신 6:13", "사 19:21", "시 76:2", "행 17:16-17", "시 16:4", "신 7:5", "사 30:22"] },
  { number: 109, question: "제2계명이 금하는 죄는 무엇입니까?", answer: "제2계명이 금하는 죄는, 하나님께서 제정하지 아니하신 그 어떤 예배를 고안하거나 의논하거나 명하거나 사용하거나 어떤 방식으로든 승인하는 것입니다. 곧 거짓된 종교를 용인하든지 , 하나님 곧 삼위 전체나 각 위격에 대한 어떤 표상을 내적으로 우리 마음속에서나 외적으로 어떤 피조물의 형상이나 모양으로 만드는 것이든지, 무릇 그 표상에게 절하거나 그 표상 안에서나 그 표상으로 하나님께 절하는 것이든지, 거짓 신들의 표상을 만들어서 무릇 그것들을 예배하고 섬기는 것이든지, 우리 스스로 만들었거나 취하였거나, 다른 이에게서 전통으로 받았거나, 고대 풍습이나 관습이나 종교적 열심이나 선의(善意)나 혹은 그 어떤 구실 아래 온갖 미신적 고안들로 하나님을 예배하는 일을 부패시키고 그것에 더하거나 그것에서 제하는 것이든지, 성직 매매 하는 것이든지, 신성 모독 하는 것이든지, 하나님께서 정하신 예배와 규례를 방해하고 반대하여 태만하고 교만한 태도를 보이는 것입니다.", references: ["민 15:39", "신 13:6-8", "호 5:12", "미 6:16", "왕상 11:33", "왕상 12:33", "신 12:30-32", "신 13:6-12", "스 13:2-3", "계 2:2, 14, 15, 20", "계 17:12, 16, 17", "신 4:15, 19", "행 17:29", "롬 1:21-23, 25", "단 3:4", "갈 4:8", "출 32:8", "왕상 18:26, 28", "사 65:11", "행 17:22", "골 2:21-23", "말 1:7, 8, 14", "신 4:2", "시 106:39", "마 15:9", "벧전 1:18", "렘 44:17", "사 65:1-5", "갈 1:13∼14", "삼상 13:11-12", "삼상 15:21", "행 8:18", "롬 2:22", "말 3:8", "출 4:24-26", "마 22:5", "말 1:7, 13", "마 23:15", "행 13:44-45", "살전 2:15-16"] },
  { number: 110, question: "제2계명을 더 잘 지키게 하려고 그 이유로 이어서 말씀하신 것이 무엇입니까?", answer: "제2계명을 더 잘 지키게 하려고 그 이유로 이어서 말씀하신 것은, “나 여호와 너의 하나님은 질투하는 하나님인즉 나를 미워하는 자의 죄를 갚되 아비로부터 아들에게로 삼사 대까지 이르게 하거니와 나를 사랑하고 내 계명을 지키는 자에게는 천 대까지 은혜를 베푸느니라” 하신 말씀에 담겨 있습니다. 곧 하나님께서 우리의 주권자이시니 우리가 마땅히 순종해야 하고, 게다가 하나님께서 예배 받으시기를 열망하시며 모든 거짓 예배를 영적 간음으로 벌하실 만큼 진노하시고, 이 계명을 위반하는 자들을 하나님을 미워하는 자로 여기시며 그들을 벌하시되 삼사 대까지 하시겠다 경고하시고, 이 계명을 지키는 자들을 하나님을 사랑하고 그의 계명들을 지키는 자로 인정하시며 그들에게 은혜 베풀되 천 대까지 하시겠다 약속하셨기 때문입니다.", references: ["출 20:5-6", "시 45:11", "계 15:3-4", "출 34:13-14", "고전 10:20-22", "렘 7:18-20", "겔 16:26-27", "신 32:16-20", "호 2:2-4", "신 5:29"] },
  { number: 111, question: "제3계명이 무엇입니까?", answer: "제3계명은 “너는 너의 하나님 여호와의 이름을 망령되이 일컫지 말라. 나 여호와의 이름을 망령되이 일컫는 자를 죄 없다 하지 아니하리라” 하신 것입니다.", references: ["출 20:7"] },
  { number: 112, question: "제3계명이 명하는 것은 무엇입니까?", answer: "제3계명이 명하는 것은 하나님의 이름과 칭호와 속성과 규례와 말씀과 성례와 기도와 맹세와 서약과 제비뽑기와 행사와 무릇 그로써 하나님께서 자기를 알리신 모든 것을 생각과 묵상과 말과 글에서 거룩한 고백과 책임 있는 삶으로써 하나님의 영광과 우리 자신과 다른 사람의 유익을 위하여 존경하는 마음으로 거룩하게 사용하라는 것입니다.", references: ["마 6:9", "신 28:58", "시 29:2", "시 68:4", "계 15:3-4", "말 1:14", "전 5:1", "시 138:2", "고전 9:24-25, 28-29", "딤전 2:8", "렘 4:2", "전 5:2", "전 4:6", "행 1:24, 26", "욥 36:24", "말 3:16", "시 8:1, 3, 4, 9", "골 3:17", "시 105:2, 5", "시 102:18", "벧전 3:15", "미 4:5", "빌 1:27", "고전 10:31", "렘 32:39", "벧전 2:12"] },
  { number: 113, question: "제3계명이 금하는 죄는 무엇입니까?", answer: "제3계명이 금하는 죄는, 하나님의 이름을 명하신 대로 쓰지 않는 것과, 하나님의 칭호와 속성과 규례와 행사를 무지하게 허망하게 불경하게 속되게 미신적으로나 사악하게 언급하거나 달리 써서 하나님의 이름을 남용하는 것과, 신성모독이나 거짓 맹세와, 모든 죄악된 저주와 맹세와 서약과 제비뽑기와, 합법적인 우리의 맹세와 서약을 위반하는 것이나 불법적인 일과 관련해서 우리의 맹세와 서약을 이루는 것과, 하나님의 작정과 섭리를 원망하거나 시비하거나 호기심으로 꼬치꼬치 알려고 하는 것이나 잘못 적용하는 것과, 속된 농담이나 호기심 어린 무익한 질문이나 공허한 말다툼이나 거짓 교리를 주장하면서 하나님의 말씀이나 그 일부를 잘못 해석하거나 잘못 적용하거나 좌우간 왜곡하는 것과, 주문(呪文)이나 죄악된 욕망과 행습에 하나님의 말씀이나 하나님의 이름 아래 포함된 피조물이나 무엇을 남용하는 것과, 하나님의 진리와 은혜와 길을 비방하거나 경멸하거나 욕하거나 어떤 식으로든 반대하는 것과, 위선으로나 사악한 목적으로 신앙고백 하는 것과, 신앙고백을 부끄러워하거나 합당치 않고 지혜롭지 않고 무익하고 부도덕하게 행함으로써 신앙고백을 모욕하거나 신앙고백을 배반하는 것입니다.", references: ["말 2:2", "행 17:23", "잠 30:9", "말 1:6-7, 12", "말3:4", "삼상 4:3-5", "렘 7:4, 9, 10, 14, 31", "골 2:20-22", "왕하 18:30, 35", "출 5:2", "시 139:20", "시 1:16-17", "사 5:13", "왕하 19:22", "레 5:7", "레 23:10", "스 5:4", "스8:17", "삼상 17:43", "삼하 16:5", "렘 5:7", "렘 23:10", "신 23:18", "행 23:13-14", "에 3:7", "에 9:24", "시 22:18", "시 24:4", "겔 17:16, 18, 19", "막 6:26", "삼상 25:22, 32-34", "롬 9:14, 19, 20", "신 29:29", "롬 3:5, 7", "롬 6:1-3", "전 8:11", "전9:3", "시 39:1-13", "마 5:21-28", "렘23:34, 36, 38", "딤전 1:4, 6-7", "딤전 6:4, 5, 20", "딤후 4:3-4", "롬 13:13-14", "왕상 21:9-10", "유 1:4", "행 13:45", "요일 3:12", "시 1:1", "벧후 3:3", "벧전 4:5", "행13:45-46, 50", "행 4:18", "행 19:9", "살전 2:16", "히 10:29", "딤후 3:5", "마 23:14", "마6:1-2, 5, 16", "막 8:38", "시 73:14-15", "고전 6:5-6", "엡 5:11-17", "사 5:4", "벧후 1:8-9", "롬 2:23-24", "갈 3:1, 3", "히 6:6", "딤후 2:14", "딛 3:9", "신 18:10-14", "행 19:13"] },
  { number: 114, question: "제3계명을 지킬 이유로 이어서 말씀하신 것은 무엇입니까?", answer: "제3계명을 지킬 이유로 이어서 말씀하신 것은 “너의 하나님 여호와”와 “나 여호와의 이름을 망령되이 일컫는 자를 죄 없다 하지 아니하리라” 하신 것인데, 곧 그분은 여호와시요 우리 하나님이시니 그분의 이름을 우리가 욕되게 하거나 어떤 방식으로든지 남용하지 말도록 하신 것이며, 특별히 여호와께서 이 계명을 범한 자들을 결코 사면하거나 용서하지 아니하실 것이니, 그들이 비록 사람의 비난과 형벌은 피할 수 있어도 그분의 의로우신 심판을 피하지 못하게 하시라는 것입니다.", references: ["출 20:7", "레 19:12", "겔 36:21-23", "신 28:58-59", "스 5:2-4", "삼상 2:12, 17, 22, 24", "삼상 3:13"] },
  { number: 115, question: "제4계명이 무엇입니까?", answer: "제4계명은 “안식일을 기억하여 거룩히 지키라. 엿새 동안은 힘써 네 모든 일을 행할 것이나, 제칠 일은 너의 하나님 여호와의 안식일인즉, 너나 네 아들이나 네 딸이나 네 남종이나 네 여종이나 네 육축이나 네 문 안에 유하는 객이라도 아무 일도 하지 말라. 이는 엿새 동안에 나 여호와가 하늘과 땅과 바다와 그 가운데 모든 것을 만들고 제칠 일에 쉬었음이라. 그러므로 나 여호와가 안식일을 복되게 하여 그날을 거룩하게 하였느니라” 하신 것입니다.", references: ["출 20:8-11"] },
  { number: 116, question: "제4계명이 명하는 것은 무엇입니까?", answer: "제4계명이 모든 사람에게 명하는 것은 하나님께서 그분의 말씀으로 정하신 일정한 시간을 하나님께 거룩하게 지키는 것, 곧 이레 중 하루를 종일토록 하나님께 거룩한 안식일로 지키라는 것입니다. 이날은 세상의 시작부터 그리스도의 부활까지는 제칠 일이었고, 이후로는 일주일의 첫날인데, 세상 끝 날까지 그러할 것입니다. 이는 기독교의 안식일이며 신약에서는 주의 날이라 불립니다.", references: ["신 5:12-14", "창 2:2-3", "고전 15:12", "행 20:7", "마 5:17-18", "사 56:2, 4, 6, 7", "계1:10"] },
  { number: 117, question: "어떻게 안식일 곧 주일을 거룩하게 지킵니까?", answer: "우리는 그날 종일을 거룩하게 쉬고 언제든지 악한 그런 일들은 물론이고 다른 날에는 정당한 세상일과 오락까지도 쉬고 또한 그날 모든 시간을 하나님께 공적으로나 개인적으로 예배드리는 데에 사용하는 것을 우리의 즐거움으로 삼음으로써 안식일을 거룩하게 지킵니다. 다만 불가피한 일과 자비를 베푸는 일은 행할 수 있습니다. 안식일을 거룩히 지키기 위하여 우리는 마음을 준비하고, 충분히 살피고 부지런하고 절제함으로써 세상일을 해결하고 적절히 처리하여 안식일의 의무를 자유롭고 적절하게 행할 수 있어야 합니다.", references: ["출 20:8, 10", "출 16:25-28", "느 13:15-22", "렘 17:21-22", "마 12:1-13", "사 58:13", "눅 4:16", "행 20:7", "고전 16:1-2", "사 66:23", "레 23:3", "출 20:8", "눅 23:54, 56", "눅 16:22, 25-26, 29", "느 13:19"] },
  { number: 118, question: "안식일을 거룩하게 지키라는 명령을 가장이나 그밖에 어른들에게 좀 더 구체적으로 베푸신 이유가 무엇입니까?", answer: "안식일을 거룩하게 지키라는 명령을 가장이나 그밖에 어른들에게 좀 더 구체적으로 베푸신 이유는 그들이 몸소 그 명령을 지켜야 할 뿐만 아니라, 자기가 돌보는 사람들이 그 명령을 지키는지 살펴야 하기 때문이고, 그들이 종종 자기 아래 사람들에게 일을 시킴으로써 안식일 성수를 방해하기 쉽기 때문입니다.", references: ["출 20:10", "수 24:15", "느 13:15, 17", "느 17:15, 17", "렘 17:20-22", "출 23:12"] },
  { number: 119, question: "제4계명이 금하는 죄는 무엇입니까?", answer: "제4계명이 금하는 죄는 명하신 의무 가운데 어느 것이라도 이행하지 않거나 부주의하고 성의 없고 무익하게 이행하고 싫증내는 것이며, 게으르거나 그 자체로 죄악적인 일을 하거나, 세상일과 오락에 관련된 불필요한 일과 말과 생각을 함으로써 그날을 더럽히는 것입니다.", references: ["겔 22:26", "행 20:7, 9", "겔 33:30-32", "암 8:5", "말 1:13", "겔 23:38", "렘 17:24, 27", "사 58:13"] },
  { number: 120, question: "제4계명을 더 잘 지키게 하려고 그 이유로 이어서 말씀하신 것이 무엇입니까?", answer: "제4계명을 더 잘 지키게 하려고 그 이유로 이어서 말씀하신 것은, “엿새 동안은 힘써 네 모든 일을 행할 것이나” 하는 말씀으로 하나님께서 우리 자신의 일을 하도록 이레 가운데 엿새를 허락하시고 자신을 위하여는 오직 하루를 떼어 두신 그 계명의 형평성과, “제칠 일은 너의 하나님 여호와의 안식일인즉” 하신 대로 그날을 특별한 소유로 주장하신 것과, “엿새 동안에 하늘과 땅과 바다와 그 가운데 모든 것을 만들고 제칠 일에 쉬”신 하나님의 모범과, “나 여호와가 안식일을 복되게 하여 그날을 거룩하게 하였느니라” 하신 대로 하나님께서 그날을 하나님을 섬기는 날로 거룩하게 하실 뿐만 아니라 우리가 그날을 거룩하게 할 때에 우리에게 복의 수단이 되도록 정하셔서 그날에 두신 그 복에 있습니다.", references: ["출 20:9-11"] },
  { number: 121, question: "제4계명의 첫머리에 ‘기억하라’는 말씀을 하신 이유가 무엇입니까?", answer: "제4계명의 첫머리에 ‘기억하라’는 말씀을 하신 이유는, 한편으로 안식일을 기억하는 데서 큰 유익을 얻기 때문인데, 우리가 안식일을 기억함으로 그날을 준비하고 그날을 지켜서 다른 모든 계명도 더 잘 지키고, 신앙을 요약하는 창조와 구원이라는 두 가지 큰 유익을 계속 감사하며 기억할 수 있기 때문이고, 다른 한편으로 우리가 안식일을 쉽게 잊어버리기 때문인데, 안식일에 관해서는 본성의 빛이 부족한 반면에 안식일에는 다른 때에 합당한 일을 행할 자유가 제한되는데, 안식일이 오되 7일에 한 번 오기에 그 사이에 많은 세상일이 생겨 우리 마음이 안식일을 생각하지 못하는 경우가 너무도 많아 그날을 준비하지 못하거나 거룩하게 하지 못할 수 있으며, 사탄이 자기 수단을 동원하여 갖은 수를 써서 안식일의 영광과 심지어 안식일의 기억조차 말살함으로써 온갖 불신앙과 불경건을 일으키기 때문입니다.", references: ["출 20:8, 16:23", "눅 23:54, 56", "막 15:42", "느 13:19", "시 92:13-14", "겔 20:12, 19, 20", "창 2:2-3", "시 118:22, 24", "행 4:10-11", "계 1:10", "겔 22:26", "느 9:14", "출 34:21", "신 5:14∼15", "암 8:5", "애 1:7", "렘 17:21-23", "느 13:15∼23"] },
  { number: 122, question: "사람에 대한 우리의 본분인 여섯 계명의 강령(綱領)이 무엇입니까?", answer: "사람에 대한 우리의 본분인 여섯 계명의 강령은 우리의 이웃을 우리 자신처럼 사랑하고, 남에게 대접을 받고자 하는 대로 우리도 대접하는 것입니다.", references: ["마 22:39", "마 7:12"] },
  { number: 123, question: "제5계명이 무엇입니까?", answer: "제5계명은 “네 부모를 공경하라. 그리하면 너의 하나님 나 여호와가 네게 준 땅에서 네 생명이 길리라” 하신 것입니다.", references: ["출 20:12"] },
  { number: 124, question: "제5계명에서 부모는 누구를 가리킵니까?", answer: "제5계명에서 부모는 단지 육신의 부모만을 가리키는 것이 아니라 나이와 은사에서 모든 윗사람과 특히 하나님의 규례에 의하여 가정과 교회와 국가에서 우리 위에 권위의 지위에 두신 사람입니다.", references: ["잠 23:22, 25", "엡 6:1-2", "딤전 5:1-2", "창 4:20-22", "잠 14:8", "왕하 5:13", "왕하 2:12", "왕하 11:14", "갈 4:19", "사 49:23"] },
  { number: 125, question: "왜 윗사람을 부모라고 부릅니까?", answer: "윗사람을 부모라고 부르는 것은 윗사람이 그들의 여러 인륜관계에서 아랫사람에 대하여 사랑과 온유함을 베푸는 모든 의무를 행할 때에 육신의 부모와 같이 하도록 가르치기 위함이고, 아랫사람으로 하여금 그들의 윗사람에 대해서 그들의 의무를 행할 때에 마치 육신의 부모에게 하듯이 더욱 자원하는 마음과 즐거움으로 행하도록 하기 위함입니다.", references: ["엡 6:4", "고후 12:14", "살전 2:7-8", "민 11:11-12", "고전 4:14-16", "왕하 5:13"] },
  { number: 126, question: "제5계명의 일반적인 범위는 무엇입니까?", answer: "제5계명의 일반적인 범위는 아랫사람과 윗사람 또는 동류(同流)와 같은 우리의 여러 인륜관계에서 서로에 대하여 지고 있는 의무를 행하는 것입니다.", references: ["엡 5:21", "벧전 2:17", "롬 12:10"] },
  { number: 127, question: "아랫사람이 윗사람에게 드려야 할 공경은 무엇입니까?", answer: "아랫사람이 윗사람에게 드려야 할 공경은 마음과 말과 행동에서 모든 합당한 경의를 표하고, 그들을 위해 기도하고 감사하며, 그들의 덕행과 미덕들을 본받고, 그들의 정당한 명령과 권고에 대해서 즐거이 순종하고, 그들의 징계에 대해서 마땅히 복종하며, 그들의 여러 신분과 그 지위의 성격을 따라서 그들의 인격과 권위에 충성하고 옹호하고 지지하며, 그들의 연약함을 참고 사랑으로 덮어 주어, 아랫사람이 윗사람과 그들의 다스림에 대해서 영예가 되게 하는 것입니다.", references: ["말 1:6", "레 19:3", "잠 31:28", "벧전 3:6", "레 19:32", "왕상 2:19", "딤전 2:1-2", "히13:7", "빌 3:17", "엡 6:1-2, 5-7", "벧전 2:13-14", "롬 13:1-5", "히 13:17", "잠 4:3-4", "잠 23:22", "출 18:19, 24", "히12:9", "벧전 2:18-20", "딛 2:9-10", "삼상 26:15-16", "삼하 18:3", "엡 6:2", "마 22:21", "롬 13:6-7", "딤전 5:17-18", "갈 6:6", "창 45:11", "창 47:12", "벧전 2:18", "잠 23:22", "창 9:23", "시 127:3-5", "잠 31:23"] },
  { number: 128, question: "아랫사람이 윗사람에 대해서 짓는 죄는 무엇입니까?", answer: "아랫사람이 윗사람에 대해서 짓는 죄는 그들에게 요구되는 의무를 소홀히 하는 모든 것과, 합당한 권고와 명령과 징계를 하는 그들의 인격과 지위를 시기하고 멸시하며 거역하는 것과, 저주하고 모욕하는 것과 및 윗사람과 그들의 다스림에 대해서 수치와 불명예가 되는 그러한 모든 완고하고 수치스러운 태도입니다.", references: ["마 15:4-6", "민 11:28-29", "삼상 8:7", "사 3:5", "삼하 15:1-12", "출 21:15", "삼상 10:27", "삼상 2:25", "단 2:18-21", "잠 30:11, 17", "잠 19:26"] },
  { number: 129, question: "윗사람이 아랫사람에 대해서 행해야 할 의무는 무엇입니까?", answer: "윗사람이 아랫사람에 대하여 행해야 할 의무는 하나님께로부터 받은 그 능력과 그들이 놓인 그 관계에 따라서 그들의 아랫사람을 사랑하고, 위하여 기도하며 복을 구하고, 그들을 가르치고 권고하고 훈계하며, 잘하는 사람은 귀히 여기고 칭찬하며 상을 주고, 잘못하는 사람은 창피를 주고 꾸짖고 징계하며, 그들을 보호하고 영혼과 몸에 필요한 모든 것을 제공하는 것이며, 또한 신중하고 현명하고 거룩하고 모범적인 행동으로 하나님께 영광이 돌아가게 하고 자신에게도 영예가 돌아오게 하여 하나님께서 그들에게 주신 권위를 보존하는 것입니다.", references: ["골 3:19", "딛 2:4", "삼상 12:23", "욥 1:5", "왕상 8:55-56", "히 7:7", "창 49:28", "신 6:6-7", "엡 6:4", "벧전 3:7", "벧전 2:4", "욥 29:12-17", "사 1:10, 17", "엡 6:4", "딤전 5:8", "딤전 4:12", "딛 2:3-5", "왕상 3:28", "딛 2:15"] },
  { number: 130, question: "윗사람의 죄는 무엇입니까?", answer: "윗사람의 죄는 그들에게 요구되는 의무들을 소홀히 하는 것 이외에, 자기의 것이나 자기 자신의 영광, 편안함, 이익, 혹은 쾌락을 과도하게 구하는 것이고, 불법한 일이나 아랫사람의 능력이 미치지 못하는 일을 행하라고 명하는 것이며, 악한 일에서 아랫사람과 의논하고 격려하며 호의를 보이는 것, 선한 일에서 아랫사람을 말리고 낙심시키거나 창피를 주는 것, 정당하지 않게 징계를 하는 것, 악과 시험과 위험에 부주의하게 노출시키거나 방치하는 것, 그들을 노엽게 하는 것, 혹은 부정당하고 경솔하고 가혹하고 게으른 행동으로 스스로를 수치스럽게 하거나 자신의 권위를 깎아내리는 것입니다.", references: ["겔 34:2-4", "빌 2:21", "요 5:44", "요7:8", "사 56:10-11", "신 17:17", "단 3:4-6", "행 4:17-18", "히 12:10", "신 25:3", "창 38:11, 26", "행 18:17", "엡 6:4", "창 9:21", "왕상 12:13-16", "왕상 1:6", "삼상 2:29-31"] },
  { number: 131, question: "동류(同流) 사이의 의무는 무엇입니까?", answer: "동류 사이의 의무는 서로 상대방의 존엄과 가치를 인정하여 존경하기를 서로 먼저 하며, 상대의 은사와 진보를 자기의 것처럼 즐거워하는 것입니다.", references: ["벧전 2:17", "롬 12:10", "롬 12:15-16", "빌 2:3-4"] },
  { number: 132, question: "동류 사이의 죄는 무엇입니까?", answer: "동류 사이의 죄는 그들에게 요구되는 의무를 소홀히 하는 것 이외에, 그 가치를 깎아내리고, 은사들을 시기하며, 상대의 진보나 번영을 유감으로 여기고, 서로 으뜸 되는 자리를 차지하려고 하는 것입니다.", references: ["롬 13:8", "딤후 3:3", "행 7:9", "갈 5:26", "민 12:2", "에 6:12-13", "요삼 1:9", "눅 22:24"] },
  { number: 133, question: "제5계명을 지킬 이유로 이어서 말씀하신 것은 무엇입니까?", answer: "제5계명을 지킬 이유로 이어서 말씀하신 것은 “그리하면 너의 하나님 나 여호와가 네게 준 땅에서 네 생명이 길리라” 하신 것으로서, 이 계명을 지키는 모든 사람이 장수하고 번영하리라는 약속입니다. 다만 하나님께 영광이 되고 그들에게 선이 되는 한, 그렇습니다.", references: ["출 20:12", "신 5:16", "왕상 8:25", "엡 6:2-3"] },
  { number: 134, question: "제6계명이 무엇입니까?", answer: "제6계명은 “살인하지 말지니라” 하신 것입니다.", references: ["출 20:13"] },
  { number: 135, question: "제6계명이 명하는 것은 무엇입니까?", answer: "제6계명이 명하는 것은 모든 세심한 생각과 정당한 노력을 기울여, 자기 자신과 다른 사람의 생명을 보존하라는 것인데, 누구의 생명이든지 부당하게 빼앗으려는 온갖 생각과 의도를 반대하고, 온갖 격분을 억제하고, 온갖 경우와 유혹과 관행을 피해야 하며, 폭력에 맞서 사람의 생명을 정당하게 방어하고, 하나님의 징계를 인내하며 받고, 마음을 고요하게 하고, 즐거운 마음을 품고, 고기나 술이나 약이나 수면이나 노동이나 오락을 절제 있게 사용해야 하며, 자비로운 생각과 사랑과 동정하는 마음과 온유함과 친절함과, 평화롭고 부드럽고 예의 바른 말과 행동과, 인내함과 화평케 함과 참고 견딤과 잘못을 용서함과 선으로 악을 갚음과 고난 당하는 자를 위로하고 구제함과 무죄한 자를 보호하고 변호해야 합니다.", references: ["엡 5:28-29", "왕상 18:4", "렘 26:15-16", "행 23:12, 16, 17, 21, 27", "엡 4:26-27", "삼하 2:22", "신 22:8", "마 4:6-7", "잠 1:10, 11, 15, 16", "삼상 24:12", "삼상 26:9-11", "창 37:21-22", "시 82:4", "잠 24:11-12", "삼상 14:45", "약 5:7-11", "히 12:19", "살전 4:11", "벧전 3:3-4", "시 37:8-11", "잠 17:22", "잠 25:16, 27", "잠 16:26", "전 3:4, 11", "삼상 19:4-5", "삼상22:13-14", "롬 13:10", "눅 10:33∼34", "골 3:12-13", "약 3:17", "벧전 3:8-11", "잠 15:1", "삿 8:1-3", "마 5:24", "엡 4:2, 32", "롬 12:17, 20, 21", "살전 5:11", "욥 31:19-20", "마 25:35-36", "잠 31:8-9"] },
  { number: 136, question: "제6계명이 금하는 죄는 무엇입니까?", answer: "제6계명이 금하는 죄는, 자기 자신의 생명이나 다른 사람의 생명을 빼앗는 모든 것인데, 공공의 정의나 정당한 전쟁이나 필수적인 방어의 경우는 예외입니다. 생명의 보존을 위한 합법적이고 필수적인 수단을 게을리하거나 쓰지 않는 것, 죄악된 분노나 미움이나 시기나 복수심, 온갖 과도한 격분이나 마음을 흩뜨리는 염려들, 고기나 술이나 노동이나 오락을 무절제하게 사용하는 것, 격동시키는 말이나 학대나 싸움이나 다툼이나 상해나, 무릇 사람의 생명을 파멸하기 쉬운 것을 금합니다.", references: ["민 35:31, 33", "렘 48:10", "신 20:5-20", "출 22:2, 3", "행 16:28", "창 9:6", "마 25:42, 43", "약 2:15, 16", "전 6:1-2", "마 5:22", "요일 3:15", "레 19:17", "잠 14:30", "롬 12:19", "엡 4:31", "약 4:1", "마 6:31, 34", "눅 21:34", "롬 13:13", "전 4:8", "전12:12", "전 2:22-23", "사 5:12", "전 9:9", "잠 15:1", "잠 12:18", "겔 18:18", "출 1:14", "갈 5:15", "잠 23:29", "민 35:16-18, 21", "출 21: 18-36"] },
  { number: 137, question: "제7계명이 무엇입니까?", answer: "제7계명은 “간음하지 말지니라” 하신 것입니다.", references: ["출 20:14"] },
  { number: 138, question: "제7계명이 명하는 것은 무엇입니까?", answer: "제7계명이 명하는 것은, 몸과 마음과 감정과 말과 행동에서 정조(貞操)를 지키는 것과, 자기 자신만 아니라 다른 사람의 정조를 보존하는 것과, 눈과 모든 감각을 주의 깊게 살피는 것과, 절제함, 순결한 사귐을 갖는 것, 단정한 옷차림과, 독신의 은사가 없는 자들의 경우에 혼인하여 부부애로 서로 동거함과, 우리의 소명에서 부지런히 일함과, 모든 부정한 일들을 멀리하고 부정으로 이끄는 유혹에 맞서는 것입니다.", references: ["살전 4:4", "요 3:1", "고전 7:34", "골 4:6", "벧전 3:2", "고전 7:2, 35, 36", "욥 31:1", "행 24:24-25", "잠 2:16-20", "딤전 2:9", "고전 7:2, 9", "잠 5:19-20", "벧전 3:17", "잠 31:11, 27, 28", "잠 5:8", "잠 39:8-10"] },
  { number: 139, question: "제7계명이 금하는 죄는 무엇입니까?", answer: "제7계명이 금하는 죄는 제7계명이 명하는 것을 소홀히 하는 것 이외에 간음과 간통과 강간과 근친상간과 동성애와 기타 본성을 거스르는 모든 정욕과, 모든 부정한 상상과 생각과 목적과 감정과, 모든 부패하고 추한 말을 하거나 그런 말을 듣는 것과, 음탕한 눈길과 뻔뻔하고 경박한 행동과 음란한 옷차림과, 합법적 혼인을 금하는 것과 불법한 혼인을 시행하는 것과, 매음(賣淫)을 허용하고 관용하고 행하거나 그런 곳으로 가는 것과, 독신 서약 하는 데에 걸려들거나, 혼인을 부당하게 미루거나, 아내나 남편을 동시에 여럿 두는 것과, 부당한 이혼이나 유기(遺棄)와, 게으름과 탐식과 술 취함과 부정한 교제와, 음탕한 노래와 책과 그림과 춤과 연극과, 우리 자신이나 다른 사람들에게 온갖 음란한 자극이나 행동을 행하는 것입니다.", references: ["잠 5:7", "히 13:4", "갈 5:19", "삼하 13:14", "고전 5:1", "롬 1:24, 26, 27", "레 20:15-16", "마 5:28", "마 15:19", "골 3:5", "엡 5:3-4", "잠 7:5, 21, 22", "사 3:16", "벧후 2:14", "잠7:10, 13", "딤전 4:3", "레 18:1-21", "막 6:18", "말 2:11-12", "왕상 15:12", "왕하 23:17", "신 23:17-18", "레 19:29", "렘 5:7", "잠 7:24-27", "마 19:10-11", "고전 7:7-9", "창 38:26", "말 2:14-15", "마 19:5", "말 2:16", "마 5:8", "엡 5:4", "겔 23:14-16", "사 23:15-17", "사 3:16", "막 6:22", "롬 13:14", "벧전 4:3", "왕하 9:30", "렘4:30", "겔 23:40"] },
  { number: 140, question: "제8계명이 무엇입니까?", answer: "제8계명은 “도둑질하지 말지니라” 하신 것입니다.", references: ["출 20:15"] },
  { number: 141, question: "제8계명이 명하는 것은 무엇입니까?", answer: "제8계명이 명하는 것은 사람 사이의 계약이나 상거래에서 진실과 성실과 공의를 행하는 것과, 각 사람에게 그의 몫을 돌리는 것과, 불법으로 차지한 재산을 그 정당한 소유자에게 돌려주는 것과, 자기 자신의 능력과 다른 사람들의 필요에 따라서 거저 주거나 빌려 주는 것과, 세상 물건들에 관한 우리의 판단과 뜻과 감정을 과도하지 않게 갖는 것과, 우리의 본성을 유지하는 데에 필요하며 편리하고 또한 우리의 형편에 적절한 세상 물건들을 얻고 소유하고 사용하고 처분할 수 있도록 신중히 살피고 궁구하는 것과, 합법적인 소명을 알고 부지런히 행하는 것과, 검소한 것과, 불필요한 소송이나 보증 혹은 그와 유사한 일을 피하는 것과, 자기 자신이나 다른 사람의 부와 재산을 모든 정당하고 합법적인 방법으로 얻고 보존하고 증진하도록 힘쓰는 것입니다.", references: ["시 15:2, 4", "스 7:4, 10", "스 8:16-17", "롬 13:7", "레 6:2-5", "눅 19:8", "눅 6:30, 38", "요 3:17", "엡 4:28", "갈 6:10", "딤전 6:6-9", "갈 6:14", "딤전 5:8", "잠 27:23-27", "전 2:24", "전 3:12-13", "딤전 6:17-18", "사 38:1", "마 11:18", "고전 7:20", "창 2:15", "창3:19", "엡 4:28", "잠 10:4", "요 6:12", "잠 21:20", "고전 6:1-9", "잠 6:1-6", "잠11:15", "레 25:35", "신 22:1-4", "출 23:4-5", "빌 2:4", "마 22:39", "창 47:14, 20"] },
  { number: 142, question: "제8계명이 금하는 죄는 무엇입니까?", answer: "제8계명이 금하는 죄는 명하신 것들을 소홀히 하는 것 이외에, 도둑질이나 강도질이나 인신매매나 훔친 물건을 사들이는 것과, 속이는 거래나 거짓된 저울과 추나 경계표를 옮기는 것이나 사람 사이의 계약이나 신의의 문제에서 불공정하고 불성실한 것과, 학대나 착취나 고리대금이나 뇌물이나 악의적인 소송이나 불공정한 재산 증식이나 약탈과, 가격을 올리려고 매점매석하는 것과, 불법적인 직업들과, 그밖에 우리의 이웃에게 속한 것을 빼앗거나 부자 되려고 온갖 불의하고 죄악된 방법을 사용하는 것과, 탐심과, 세상 물건들을 과도하게 얻거나 즐거워하는 것과, 세상 물건들을 얻고 유지하고 사용하려고 믿음 없이 염려하고 애쓰는 나머지 마음을 빼앗기는 것과, 다른 사람의 재산을 시기하는 것과, 게으른 것이나 낭비하는 것이나 쓸데없이 내기하는 것과, 그밖에 자기의 재산에 부당하게 손해를 입히거나 하나님께서 주신 재산을 정당하게 사용하거나 즐거워하지 않는 것입니다.", references: ["약 2:15-16", "요 3:17", "엡 4:28", "시 62:10", "딤전 1:10", "잠 29:24", "살전 4:6", "잠 11:1", "잠 20:10", "신 19:14", "잠 23:25", "겔 22:12", "시 15:15", "욥 15:34", "고전 6:6-8", "잠 3:29-30", "사 5:8", "미 2:2", "잠 11:26", "행 19:19, 24, 25", "욥 20:19", "약 5:4", "잠 21:6", "눅 12:15", "딤전 6:5", "골 3:2", "잠 23:5", "시 62:10", "마 6:25, 31, 34", "전 5:12", "시 73:3", "시 37:1, 7", "살후 3:11", "잠 18:9", "잠 21:17", "잠 23:20, 21", "잠 28:19", "전 4:8", "전 6:2", "딤전 5:8"] },
  { number: 143, question: "제9계명이 무엇입니까?", answer: "제9계명은 “네 이웃에 대하여 거짓 증거 하지 말지니라” 하신 것입니다.", references: ["출 20:16"] },
  { number: 144, question: "제9계명이 명하는 것은 무엇입니까?", answer: "제9계명이 명하는 것은 사람 사이의 진실함이나 자기 자신과 이웃의 명예를 지키고 증진하는 것과, 진실을 위하여 나서서 옹호하는 것과, 재판과 정의의 문제에서와 그밖에 다른 모든 일에서 마음으로부터, 진지하게, 자유롭게, 분명하게, 충분하게 진실을 말하되, 오직 진실만을 말하는 것과, 우리 이웃을 사랑으로 존경하는 것과, 이웃의 명예를 좋아하고 바라며 기뻐하는 것과, 이웃의 연약함을 슬퍼하고 덮어 주는 것과, 이웃의 은사와 덕을 기꺼이 인정하는 것과, 이웃의 결백을 변호하는 것과, 이웃에 관한 좋은 소문을 흔쾌히 받아들이지만 나쁜 소문은 인정하기를 꺼려하는 것과, 험담하는 사람과 아첨하는 사람과 중상하는 사람을 막는 것과, 좋은 평판 얻기를 좋아하고 힘쓰며 필요할 경우에 그것을 변호하는 것과, 합법적인 약속을 지키는 것과, 무엇이든지 진실하고 정직하고 사랑스럽고 명예에 속하는 것을 궁구하고 실천하는 것입니다.", references: ["스 8:16", "요삼 1:12", "잠 31:8∼9", "시 15:2", "대하 19:9", "삼상 19:4-5", "수 7:19", "삼하 14:18-20", "레 19:15", "잠14:5, 25", "고후 1:17-18", "엡 4:25", "히 6:9", "고전 13:7", "롬 1:8", "요삼 1:3, 4", "고전 1:4, 5, 7", "딤후 1:4∼5", "삼상 12:14", "고전 13:6-7", "시 15:3", "잠 25:23", "잠26:24", "시 101:5", "잠 22:1", "요 8:49", "시 15:4", "빌 4:8", "고후 2:4", "고후 12:21", "잠 17:9", "벧전 4:8"] },
  { number: 145, question: "제9계명이 금하는 죄는 무엇입니까?", answer: "제9계명이 금하는 죄는 진실을 훼손하거나 특히 재판에서 자기 자신과 우리의 이웃의 명예를 훼손하는 모든 것과, 거짓 증거를 제시하거나 거짓 증인을 매수하거나 의도적으로 악한 소송에 나서서 변호하거나 진실을 뒤집어엎는 것과, 불의한 판결을 내거나 악을 선이라 하고 선을 악이라 하는 것과, 악한 사람을 의로운 사람의 행위에 따라 보상하거나 의로운 사람을 악한 사람의 행위에 따라 갚아 주는 것과, 위조나 진실을 숨기는 것이나 정의로운 소송에 부당하게 침묵하는 것이나 불의를 보고 책망해야 할 때나 불의로 다른 사람이 피해 당할 때에 가만히 있는 것과, 진실이나 공의를 훼손할 목적으로 때에 맞지 않게 진실을 말하거나 그릇된 목적을 위하여 악의적으로 진실을 말하거나 그릇된 의미로나 의심스럽고 애매모호한 표현으로 진실을 왜곡하는 것과, 진실 아닌 것을 말하거나 거짓말하거나 중상(中傷)하거나 험담하거나 남을 나쁘게 말하거나 헐뜯거나 수군수군하거나 조롱하거나 비방하거나 경솔하거나 사납거나 편파적으로 비판하는 것과, 나쁘게 해석하려는 의도나 말이나 행동과, 아첨하는 것이나 허영심으로 자랑하는 것과, 자기 자신이나 다른 사람을 지나치게 높게 혹은 지나치게 낮게 생각하거나 말하는 것과, 하나님의 은사와 은혜를 부인하는 것과, 사소한 잘못을 과장하는 것과, 죄를 기꺼이 고백해야 할 때에 그 죄를 숨기거나 변명하거나 약화하는 것과, 약점을 쓸데없이 찾아내는 것과, 거짓된 소문을 조장하거나 악한 평판을 받아들이고 묵인하거나 의로운 변호에 귀를 막는 것과, 나쁜 의심과, 어떤 사람이 받아 마땅한 신뢰를 시기하거나 불만스러워하는 것이나 그것을 훼손하려고 애쓰거나 바라는 것이나 다른 사람의 불명예나 수치를 기뻐하는 것과, 경멸에 찬 조롱이나 맹목적인 숭배와, 합법적인 약속을 위반하는 것과, 명예와 같은 것을 무시하거나 오명을 뒤집어쓰는 것과 같은 그런 일을 하든지 그런 일을 회피하지 않든지 다른 사람이 그런 일을 당하지 않도록 방지하지 않는 것입니다.", references: ["삼상 17:28", "삼하 16:3", "삼하1:9-10, 15-16", "레 19:15", "히 1:4", "잠 19:5", "잠 6:16, 19", "행 6:13", "렘 9:3, 5", "행 24:2, 5", "시 12:3-4", "시 52:1-4", "잠 17:15", "왕상 21:9-14", "사 5:23", "시 119:69", "눅 19:8", "눅 16:5-7", "레 5:1", "신 13:8", "행 5:3, 8, 9", "딤후 4:16", "왕상 1:6", "레 19:7", "사 59:4", "잠 29:11", "삼상 22:9-10, 5", "시 52:1-5", "시 56:5", "요 2:19", "마 26:60-61", "창 3:5", "창 26:7, 9", "사 59:13", "레 19:11", "골 3:9", "시 1:20", "시 15:3", "약 4:11", "렘 38:4", "레 19:16", "롬 1:29-30", "창 21:9", "갈 4:29", "고전 6:10", "마 7:1", "행 28:4", "창 38:24", "롬 2:1", "느 6:6-8", "롬 3:8", "시 69:10", "삼상 1:13-15", "삼상 16:3", "시 12:2-3", "딤후 3:9", "눅 18:9, 11", "롬 12:16", "고전 4:6", "행 12:23", "출 4:10-14", "렘 17:5-6", "렘 4:6", "마 7:3∼5", "잠 28:13", "잠 30:20", "창 3:12-13", "렘 2:35", "왕하 5:25", "창 4:9", "창 9:22", "잠 25:9-10", "출 23:1", "잠 29:12", "행 7:56-57", "욥 31:13-14", "고후 13:5", "딤전 6:4", "민 11:29", "마 21:15", "스 4:12-13", "렘 48:27", "시 35:15-16, 21", "마 27:28-29", "유 1:16", "행 12:22", "롬 1:41", "딤후 3:3", "삼상 2:24", "삼하 13:12-13", "잠 5:8-9", "잠 6:33"] },
  { number: 146, question: "제10계명이 무엇입니까?", answer: "제10계명은 “네 이웃의 집을 탐내지 말지니라. 네 이웃의 아내나 그의 남종이나 그의 여종이나 그의 소나 그의 나귀나 무릇 네 이웃의 소유를 탐내지 말지니라” 하신 것입니다.", references: ["출 20:17"] },
  { number: 147, question: "제10계명이 명하는 것은 무엇입니까?", answer: "제10계명이 명하는 것은 자기 자신의 처지에 온전히 만족하며, 우리 이웃이 잘되기를 바라는 마음을 가져 그를 향한 우리 마음의 모든 동기와 애정이 그가 소유한 모든 선한 것에까지 미치게 하라는 것입니다.", references: ["히 13:5", "딤전 6:6", "욥 31:29", "롬 12:15", "시 122:7-9", "딤전 1:5", "에 10:3", "고전 13:4-7"] },
  { number: 148, question: "제10계명이 금하는 죄는 무엇입니까?", answer: "제10계명이 금하는 죄는 자기 자신의 처지를 조금이라도 불만스러워 하고, 우리 이웃의 잘됨을 시기하고 원통하게 여기고서 이웃의 것에 대하여 조금이라도 부당한 마음과 욕심을 품는 것입니다.", references: ["왕상 21:4", "에 5:13", "고전 10:10", "갈 5:26", "약 3:14, 16", "시 112:9-10", "느 2:10", "롬 7:7, 8:9", "골 3:5", "신 5:21"] },
  { number: 149, question: "하나님의 계명을 완전히 지킬 수 있는 사람이 있습니까?", answer: "사람은 스스로나 혹은 이 세상에 살 동안에 받은 어떤 은혜로써 하나님의 계명을 완전히 지킬 수 없고, 오히려 생각과 말과 행위로 날마다 범합니다.", references: ["약 3:2", "요 15:15", "롬 8:3", "전 7:20", "요 1:8, 10", "갈 5:17", "롬 7:18-19", "창 6:5, 8:21", "롬 3:9", "약 3:2-13"] },
  { number: 150, question: "하나님의 법을 어기는 모든 죄가 그 자체로 또한 하나님 보시기에 똑같이 가증합니까?", answer: "하나님의 법을 어기는 모든 죄가 똑같이 가증한 것은 아니고, 어떤 죄는 그 자체로서 그리고 여러 가지 가중 요인으로 말미암아 하나님 보시기에 다른 죄보다 더 가증합니다.", references: ["요 19:11", "겔 8:6, 13, 15", "요 5:16", "시 8:17, 32, 56"] },
  { number: 151, question: "어떤 죄를 다른 죄보다 더 가증하게 만드는 가중 요인은 무엇입니까?", answer: "죄의 가중 요인은 첫째로 죄 범한 사람과 관련됩니다. 이는 죄 범한 사람이 성숙한 나이든지, 경험이나 은혜를 많이 가졌든지, 소명과 은사와 위치와 직분에서 뛰어나든지, 다른 사람을 인도하는 사람이든지 다른 사람이 따르기 쉬운 본보기가 되는 경우입니다. 둘째로는 피해를 당한 당사자와 관련됩니다. 이는 하나님과 그분의 속성과 그분을 향한 예배를 직접 거스르거나 그리스도와 그분의 은혜를 거스르거나 성신과 그분의 증거와 역사하심을 거스르거나 손윗사람이나 높은 사람을 거스르거나 특별히 가깝고 관계있는 사람을 거스르거나 성도들 특히 약한 형제와 그들이나 다른 사람의 영혼과 모든 사람이나 다수의 공공선을 거스르는 경우입니다.", references: ["렘 2:8", "욥 32:7, 9", "전 4:13", "왕상 11:4, 9", "삼하 12:14", "고전 15:1", "약 4:17", "눅 12:47-48", "렘 5:4-5", "삼하 12:8-9", "겔 8:11-12", "롬 2:17-24", "갈 2:11-14", "마 21:38-39", "삼상 2:25", "행 5:4", "시 51:4", "롬 2:4", "말 1:8, 14", "히 2:2-3", "히 12:25", "히 10:29", "마 12:31-32", "엡 4:30", "히 6:4-6", "유 1:8", "민 12:8-9", "사 3:5", "잠 30:17", "고후 12:15", "시 55:12-15", "스 2:8, 10, 11", "마18:6", "고전 6:8", "계 17:6", "고전 8:11-12", "롬 14:13, 15, 21", "겔 13:19", "고전 8:12", "계 18:12-13", "마 23:15", "살전 2:15-16", "수 22:20", "잠 6:30-33", "스 9:10-12", "왕상 11:9-10", "골 3:5", "딤전 6:10", "잠 5:8-12", "잠 6:32-33", "요 15:22", "사 1:3", "신 32:6", "암 4:8-11", "렘 5:3", "롬 1:26-27", "롬1:32", "단 5:22", "잠 29:1", "딛 18:17", "잠 27:22", "잠 23:35", "시 78:34-37", "렘 2:20", "렘13:5, 6, 20, 21", "전 5:4-6", "잠 20:25", "레 26:25", "잠 2:17겔 17:18-19", "시 36:4", "렘 6:16", "민 15:30", "출 21:14", "렘 3:3", "잠 7:13", "시 52:1", "요삼1:10", "민 16:22", "스 7:11-12", "잠 2:14", "사 57:17", "렘 34:8-11", "벧후 2:20-22", "왕하 5:26", "렘 7:10", "사 26:10", "겔 23:37-39", "사 58:3-5", "민 25:6-7", "고전 11:20-21", "렘 7:8-10", "잠 7:14-15", "요 13:27, 30", "스 9:13-14", "삼하 15:22", "삼상 2:22-24"] },
  { number: 152, question: "모든 죄가 하나님의 손에서 받아 마땅한 것은 무엇입니까?", answer: "모든 죄는, 가장 작은 죄라도 하나님의 주권과 선하심과 거룩하심을 거스르고, 그분의 의로운 법을 거스르는 것이므로, 이생에서와 내세에서 그분의 진노와 저주를 받아 마땅합니다. 모든 죄는 오직 그리스도의 피가 아니면 사함 받을 수 없습니다.", references: ["약 2:10-11", "출 20:1-2", "말 1:14", "신 32:6", "합 1:13", "레 10:3", "레 11:44-45", "벧전 1:15-16", "요일 3:4", "롬 7:12", "엡 5:6", "갈 3:10", "엡 5:6", "애 3:39", "신 28:15-68", "잠 13:21", "롬 6:21, 23", "마 25:41", "히 9:22", "벧전 1:18-19"] },
  { number: 153, question: "우리가 율법을 위반한 까닭에 받아 마땅한 하나님의 진노와 저주를 피할 수 있도록 하나님께서 우리에게 요구하시는 것은 무엇입니까?", answer: "우리가 율법을 위반한 까닭에 받아 마땅한 하나님의 진노와 저주를 피할 수 있도록 하나님께서 우리에게 요구하시는 것은, 하나님을 향하여 회개하고, 우리 주 예수 그리스도를 믿고, 그리스도께서 중보 사역의 유익을 우리에게 주시려고 쓰시는 외적인 방도를 부지런히 사용하는 것입니다.", references: ["행 20:21", "마 3:7-8", "눅 13:3, 5", "행 16:30-31", "요 3:16, 18", "잠 2:1-5, 8:33-36"] },
  { number: 154, question: "그리스도께서 중보 사역의 유익을 우리에게 주려고 쓰시는 외적인 방도들은 무엇입니까?", answer: "그리스도께서 중보 사역의 유익을 자기 교회에게 주려고 쓰시는 외적이고 통상적인 방도들은 그분이 정하신 모든 규례인데, 특히 말씀과 성례와 기도입니다. 이 모든 것이 택함 받은 사람들에게 그들의 구원을 위하여 효력 있게 됩니다.", references: ["마 28:19-20", "행 2:42, 46, 47"] },
  { number: 155, question: "말씀이 어떻게 구원을 위하여 효력 있게 됩니까?", answer: "하나님의 성신께서 말씀의 낭독, 특별히 강설을 효력 있는 방도로 쓰셔서, 죄인에게 빛을 비추어 죄를 깨닫게 하며 겸손하게 하고, 그들을 자기 자신에게서 벗어나 그리스도에게로 이끌고, 그들로 하여금 그리스도의 형상을 닮게 하며 그분의 뜻에 복종하게 하고, 그들에게 힘주어 시험과 부패를 대적하게 하고, 그들을 은혜 가운데 세워 주며 믿음으로 구원에 이르게 합니다.", references: ["느 8:8", "행 26:18", "시 19:8", "고전 14:24-25", "대하 34:18-19, 26-28", "행 2:37, 41", "행 8:27-39", "고후 3:18", "고후10:4-6", "롬 6:17", "마 4:4, 7, 10", "엡6:16-17", "시 19:11", "고전 10:11", "행 20:32", "딤후 3:11-17", "롬 16:25", "살전 3:2, 10, 11, 13", "롬 15:4", "롬 10:13-17", "롬1:16"] },
  { number: 156, question: "하나님의 말씀을 모든 사람이 읽어야 합니까?", answer: "모든 사람이 공적으로 회중에게 말씀을 낭독하도록 허락된 것은 아니지만, 누구든지 각자 홀로 그리고 가족과 함께 성경을 읽어야 합니다. 이 목적을 위하여 성경은 원어에서 자국어로 번역되어야 합니다.", references: ["신 31:9, 11-13", "느 8:2-3", "느 9:3-5", "신 11:19", "계 1:3", "요 5:39", "사 34:16", "신 6:6∼9", "창 18:17, 19", "시 78:5-7", "고전 14:6, 9, 11-12, 15-16, 24, 27-28"] },
  { number: 157, question: "하나님의 말씀을 어떻게 읽어야 합니까?", answer: "성경을 읽을 때에는 높이 받들고 경외하는 태도로, 성경이 하나님의 말씀이며 하나님만이 우리로 하여금 성경을 깨달을 수 있게 하신다는 굳은 확신을 지니고, 성경에 계시된 하나님의 뜻을 알고 믿고 순종하려는 열의를 품고, 부지런함으로 성경의 주제와 내용에 주의하면서, 묵상하며 적용하며 자기를 부인하며 기도해야 합니다.", references: ["시 19:10", "느 8:3-10", "출 24:7", "대하 34:27", "사 66:2", "벧후 1:19-21", "눅 24:25", "고후 3:13-16", "신 17:19-20", "행 17:11", "행 8:30, 34", "눅 10:26-28", "시 1:2", "시 119:97", "대하 34:21", "잠 3:5", "신 33:3", "잠 2:1-6", "시 119:18", "느 8:6, 8"] },
  { number: 158, question: "누가 하나님의 말씀을 전해야 합니까?", answer: "하나님의 말씀은 오직 충분한 은사를 갖추고, 정당한 공인을 받아 이 직분으로 부르심을 받은 사람이 전해야 합니다.", references: ["딤전 3:2, 6", "엡 4:8-11", "호 4:6", "말 2:7", "고후 3:6", "렘 14:15", "롬 10:15", "히 15:4", "고전 12:28∼29", "딤전 3:10", "딤전 4:14", "딤전 5:22"] },
  { number: 159, question: "부르심을 받은 사람은 하나님의 말씀을 어떻게 전해야 합니까?", answer: "말씀의 사역에 수고하도록 부르심을 받은 사람은 바른 교훈을 전해야 하는데, 부지런히, 때를 얻든지 얻지 못하든지, 명백하게, 사람의 지혜의 권하는 말이 아니라 성신의 나타남과 능력으로, 신실하게, 하나님의 모든 뜻을 알게 하고, 지혜롭게, 듣는 이의 필요와 능력에 알맞도록 하고, 열의를 품고, 하나님과 하나님의 백성의 영혼을 향한 뜨거운 사랑으로, 성심으로, 하나님의 영광과 그들의 회개와 건덕(建德)과 구원을 추구해야 합니다.", references: ["딛 2:1, 8", "행 18:25", "딤후 4:2", "고전 14:19", "고전 2:4", "렘 23:28", "고전 4:1-2", "행 20:27", "골 1:28", "딤후 2:15", "고전 3:2", "히 5:12-14", "눅 12:42", "행 18:25", "고후 5:13-14", "빌1:15-17", "골 4:12", "고후 12:15", "고후 2:17", "고후 4:2", "살전 2:4-6", "요 7:8", "고전 9:19-22", "고후 12:19", "엡 4:13", "딤전 4:14", "행 26:16-18"] },
  { number: 160, question: "전파된 말씀을 들을 때에 어떻게 들어야 합니까?", answer: "전파된 말씀을 들을 때에는 부지런함과 준비와 기도로써 말씀에 집중하고, 듣는 말씀을 성경으로 살피고, 믿음과 사랑과 온유함과 간절한 마음으로 진리를 하나님의 말씀으로 받아들이고, 그 진리를 묵상하며 함께 이야기하고, 그 진리를 마음에 두고 자기의 삶에서 그 열매를 맺어야 합니다.", references: ["잠 8:34", "벧전 2:1-2", "눅 8:18", "시 119:18", "엡 6:18-19", "행 17:11", "히 4:2", "살전 2:10", "약 1:21", "행 17:11", "살전 2:13", "눅 9:44", "히 2:1", "눅 24:14", "신 6:6-7", "잠 2:1", "시 119:11", "눅 8:15", "약 1:25"] },
  { number: 161, question: "성례가 어떻게 효력 있는 구원의 방도가 됩니까?", answer: "성례가 효력 있는 구원의 방도가 되는 것은 성례 자체의 무슨 능력이나 성례를 행하는 사람의 경건이나 의도에서 나오는 무슨 덕 때문이 아니고, 오직 성신의 일하심과 성례를 제정하신 그리스도의 복 주심 때문입니다.", references: ["벧전 3:21", "행 8:13, 23", "고전 3:6-7", "고전 12:13"] },
  { number: 162, question: "성례가 무엇입니까?", answer: "성례는 그리스도께서 자기의 교회에 제정하신 거룩한 규례인데, 이는 은혜 언약에 속한 사람들에게 그분의 중보 사역의 유익들을 표하고 인 치며 제시하고, 그들의 믿음과 다른 모든 은혜들을 강화하며 많아지게 하고, 그들로 하여금 순종에 이르도록 하고, 그들의 사랑과 교제를 서로 입증하며 간직하고, 그들을 바깥사람들과 구별하기 위함입니다.", references: ["창 17:7, 10", "출 12:1-51", "마 28:19", "마 26:26-28", "롬 4:11", "고전 11:24-25", "롬 15:8", "출 12:48", "행 2:38", "고전 10:16", "롬 4:11", "갈 3:27", "롬 6:3-4", "고전 10:21", "엡 4:2-5", "고전 12:13", "엡 2:11", "창 34:14"] },
  { number: 163, question: "성례의 요소는 무엇입니까?", answer: "성례의 요소는 둘인데, 첫째는 그리스도께서 친히 정하신 대로 사용되는 외적이고 감각적인 표이고, 둘째는 그것으로 표시되는 내적이고 신령한 은혜입니다.", references: ["마 3:11", "벧전 3:21", "롬 2:28-29"] },
  { number: 164, question: "그리스도께서 신약 아래 그분의 교회에 제정하신 성례는 몇입니까?", answer: "그리스도께서는 신약 아래 그분의 교회에 세례와 성찬 이 두 성례만 제정하셨습니다.", references: ["마 28:19", "고전 11:20, 23", "마 26:26-30"] },
  { number: 165, question: "세례가 무엇입니까?", answer: "세례는 그리스도께서 제정하신 신약의 성례인데, 물로 씻어 아버지와 아들과 성신의 이름 안으로 연합시키는 이 성례는 그리스도 안으로 접붙여짐과, 그리스도의 피로 죄 사함과, 그분의 성신으로 거듭남과, 양자 삼으심과, 영생에 이르는 부활을 표시하고 인 칩니다. 이로써 세례 받은 사람은 보이는 교회에 속하도록 엄숙히 허락 받고, 전적으로 오직 주님의 것이 되겠다고 공적으로 밝히 서약하게 됩니다.", references: ["행 8:36-37", "행 2:38", "창 17:7, 9", "갈 3:9, 14", "골 2:11-12", "행 2:38-39", "롬 4:11-12", "고전 7:14", "마 28:19", "눅 18:15-16", "롬 11:16"] },
  { number: 166, question: "세례는 어떤 사람에게 베풉니까?", answer: "세례는 보이는 교회 밖에 있는 사람에게 베풀지 않고, 따라서 약속의 언약 밖에 있는 사람이 그리스도를 믿고 주님께 순종하겠다고 고백할 때에 비로소 베풉니다. 또한 그리스도를 믿고 주님께 순종하겠다고 고백하는 부모 양편 혹은 한편의 유아들이 그런 점에서 언약 안에 있으므로 세례를 받아야 합니다.", references: ["행 8:36-37", "행 2:38", "창 17:7, 9", "갈 3:9, 14", "골 2:11-12", "행 2:38-39", "롬 4:11-12", "고전 7:14", "마 28:19", "눅 18:15-16", "롬 11:16"] },
  { number: 167, question: "우리가 어떻게 우리의 세례를 계속 효력 있게 할 수 있습니까?", answer: "우리가 평생토록 우리의 세례를 계속 효력 있도록 해야 할 의무가 절실할지라도 이 의무를 매우 소홀하게 대할 수 있는데, 특별히 시험 받을 때에, 다른 사람에게 세례가 시행되는 자리에 참석할 때에 그렇습니다. 우리가 우리의 세례를 계속 효력 있게 하려면, 세례의 본질과, 그리스도께서 세례를 제정하신 목적과, 세례를 통하여 주시고 인 치시는 특권과 유익들과, 세례 받을 때에 우리가 행한 엄숙한 맹세를 진지함과 감사함으로 살펴야 하고, 우리의 죄악되고 더러운 것과, 우리가 세례의 은혜와 우리의 서약에 미치지 못하고, 거기에 거슬러 행한 것 때문에 겸비해야 하고, 이 성례로 우리에게 인 치신 죄 사함과 다른 모든 복에 대한 확신을 향해 자라야 하고, 죄를 죽이고 은혜를 살리기 위하여 우리가 세례로 연합된 그리스도의 죽으심과 부활로부터 힘을 얻어야 하고, 세례로 자기 이름을 그리스도에게 바친 사람답게 믿음으로 살고 거룩함과 의 가운데 살며 한 성신으로 세례 받아 한 몸에 속하게 된 것같이 형제 사랑 가운데 행해야 합니다.", references: ["골 2:11", "욥 6:4, 6, 11", "롬 6:3-5", "고전 1:11-13", "롬 6:2-3", "롬 4:11-12", "벧전 3:21", "롬 6:3-5", "갈 3:26-27", "행 2:38", "롬 6:22", "고전 12:13, 25-27"] },
  { number: 168, question: "주님의 성찬이 무엇입니까?", answer: "주님의 성찬은 그리스도께서 정하신 대로 떡과 포도주를 주고 받음으로써 그의 죽으심을 나타내 보이는 신약의 성례입니다. 주님의 성찬을 합당하게 받는 사람은 그의 몸과 피를 먹고 마심으로 신령한 양식을 얻어 은혜 안에서 장성하고, 그리스도와 연합되고 교제함에서 더욱 견고해지고, 감사함과 하나님께 대한 서약과 동일한 신비한 몸의 지체들로서 서로 사랑과 교제를 증명하고 새롭게 합니다.", references: ["눅 22:20", "마 26:26-28", "고전 11:23-26", "고전 10:16", "고전 11:24", "고전 10:14-16, 21", "고전 10:17"] },
  { number: 169, question: "그리스도께서 주님의 성찬에서 떡과 포도주를 어떻게 주고 받도록 정하셨습니까?", answer: "그리스도께서 말씀의 사역자를 세우셔서 이 주님의 성찬의 성례를 거행할 때에 제정의 말씀과 감사와 기도로써 떡과 포도주를 통상적인 용도로부터 구별하고, 떡을 들고 떼어서 떡과 포도주를 둘 다 성찬에 참여하는 사람에게 주게 하셨습니다. 성찬에 참여하는 사람은 주님께서 정하신 대로 떡을 받아 먹고 포도주를 마시되, 자신을 위하여 그리스도의 몸이 찢어지고 주어졌으며 그리스도의 피가 흘려진 것을 감사하는 마음으로 기억해야 합니다.", references: ["고전 11:23-24", "마 26:26-28", "마 14:22-24", "눅 22:19-20"] },
  { number: 170, question: "주님의 성찬에 합당하게 참여하는 사람들은 어떻게 주님의 몸과 피를 먹고 마십니까?", answer: "그리스도의 몸과 피는 주님의 성찬에서 물질적으로나 육신적으로 떡과 포도주 안에 혹은 그것들과 함께 혹은 그것들 아래에 있지 않지만, 떡과 포도주가 그것들을 받는 사람들의 감각에 참되고 실제적으로 현존하는 것만큼 그들의 믿음에 영적으로 임재합니다. 그러므로 주님의 성찬의 성례에 합당하게 참여하는 사람들은 물질적이나 육신적인 방식이 아니라 영적인 방식으로 그리스도의 몸과 피를 먹고 마십니다. 그러나 그들이 믿음으로 십자가에 달리신 그리스도와 그분의 죽으심의 모든 유익을 받아 자신에게 적용할 때에 그것은 참되고 실제적입니다.", references: ["행 3:21", "마 26:26, 28", "고전 11:24-29", "고전 10:16"] },
  { number: 171, question: "주님의 성찬의 성례를 받는 사람들은 성찬에 나아가기 전에 어떻게 준비해야 합니까?", answer: "주님의 성찬의 성례를 받는 사람들은 성찬에 나아가기 전에, 먼저 자신이 그리스도 안에 있는지 자기의 죄와 부족이 무엇인지 자기의 지식, 믿음, 회개, 하나님과 형제를 향한 사랑, 모든 사람을 향한 사랑, 자기에게 죄 지은 이를 용서함에서 어느 정도이고 과연 진실한지에 관하여, 또한 그리스도를 향하여 열심을 품고 새롭게 순종하려고 하는지에 관하여 살피고, 진지한 묵상과 뜨거운 기도로써 이런 은혜들을 새롭게 실천하려는 태도로써 준비해야 합니다.", references: ["고전 11:28", "고후 13:5", "고후 5:7", "출 12:15", "고전 11:29", "고전 13:5", "마 26:28", "스 12:10", "고전 11:31", "고전 10:16-17", "행 2:46-47", "고전 5:8", "고전11:18, 20", "마 5:23-24", "사 55:1", "요 7:37", "고전 5:7-8", "고전 11:25-26, 28", "히 10:21, 22, 24", "시 26:6", "고전 11:24-25", "대하 30:18-19", "마 26:26"] },
  { number: 172, question: "자기가 그리스도 안에 있는 것이나 자기가 합당한 준비가 되었는지 의심하는 사람이 주님의 성찬에 나아갈 수 있습니까?", answer: "자기가 그리스도 안에 있는지 혹은 자기가 주님의 성찬의 성례에 합당한 준비가 되었는지 의심하더라도 그 점에 관하여 아직 확신에 이르지 못하였을 뿐이지 참으로 그리스도 안에 있는 사람일 수 있습니다. 그가 그리스도 안에 있지 아니하는 것을 두려워하는 마음을 정당하게 갖는다면 하나님이 판단하실 때에 틀림없이 그 사실을 소유하고 있어서 그리스도 안에서 발견되고 불의에서 떠나기를 진실하게 갈구합니다. 그 경우에 (연약하고 의심하는 그리스도인이라도 구원받을 수 있게 약속들이 주어졌고, 또한 이 성례가 제정되었으므로) 그는 자신의 불신을 애통하며 의심이 해소되기를 힘쓸 것입니다. 그렇게 함으로써 그는 주님의 성찬에 나올 수 있고 또 나와야 하며 그리하여 더욱 강건함을 얻을 것입니다.", references: ["사 1:10", "요일 5:13", "시 88:1-18", "시 77:1-12", "요 2:4, 7", "사 54:7-10", "마 5:3-4", "시 31:22", "시 73:22-23", "빌 3:8-9", "시 10:17", "시 42:1, 2, 5, 11", "딤후 2:19", "사 1:10", "시 66:18-20", "사 4:11, 29, 31", "마 11:28", "마 12:20", "마 26:28", "막 9:24", "행 2:37", "행 16:30", "롬 4:11", "고전 11:28"] },
  { number: 173, question: "믿음을 고백하고 주님의 성찬에 나오기를 바라는 사람을 성찬에서 제외시킬 수 있습니까?", answer: "믿음을 고백하고 주님의 성찬에 나오기를 바랄지라도 무지하거나 추문(醜聞)이 붙은 사람은 교훈을 받고 회개를 나타낼 때까지 그리스도께서 교회에 두신 권세로써 성찬에서 제외시킬 수 있고 제외시켜야 합니다.", references: ["고전 11:27-34", "마 7:6", "고전 5:1-13, 23", "고전 5:22, 2:7"] },
  { number: 174, question: "주님의 성찬의 성례를 받는 사람들은 성찬이 시행되는 동안에 어떻게 해야 합니까?", answer: "주님의 성찬의 성례를 받는 사람들은 성찬이 시행되는 동안에 모든 거룩한 경외심과 관심으로써 그 규례에서 하나님을 섬기고, 부지런히 성례의 요소들과 행위를 주목하고, 주의 깊게 주님의 몸을 분별하고, 사랑의 심정으로 주님의 죽으심과 고난을 묵상하고, 그리하여 깨어 그들의 은덕들을 활발하게 발휘하여서 자기를 살펴 죄를 슬퍼하며, 주리고 목말라 하듯이 그리스도를 열렬히 추구하되 믿음으로 그분을 먹고 그분의 충만에서 받고 그분의 공로를 의지하고 그분의 사랑을 즐거워하고 그분의 은혜를 감사하며, 하나님과의 언약과 모든 성도를 향한 사랑을 새롭게 해야 합니다.", references: ["레 10:3", "히 12:28", "시 5:7", "고전 11:17, 26, 27", "출 24:8", "마 26:28", "고전 11:29", "눅 22:19", "고전 11:26", "고전 10:3-5, 11, 14", "고전 11:31", "스 12:10", "계 22:17", "요 6:35", "요1:16", "빌 3:9", "시 58:4-5", "대하 30:21", "시 22:26", "렘 1:5", "시 1:5", "행 2:42"] },
  { number: 175, question: "주님의 성찬의 성례를 받은 후에 그리스도인들의 의무는 무엇입니까?", answer: "주님의 성찬의 성례를 받은 후에 그리스도인들의 의무는 성찬에서 자신이 어떻게 행하였고 그 결과가 무엇인지를 진지하게 살피는 것입니다. 만일 그들이 소생함과 위로를 발견한다면, 그로 인하여 하나님을 찬송하고 그 가운데 계속 거하기를 구하고 다시 죄 짓지 않도록 주의하고 서약을 이루고 힘을 내어 그 규례에 늘 참여할 것입니다. 그러나 만일 당장 유익을 얻지 못한다면, 더욱 엄격하게 성례를 준비하는 일과 성례에 참석하는 일을 다시 살필 것입니다. 두 경우에 만일 그들이 하나님 앞과 그들의 양심에 비추어 가납(嘉納)된다고 생각하면, 적절한 때에 성찬의 열매를 주실 것을 기다려야 합니다.", references: ["시 28:7", "시 85:8", "고전 11:17, 30, 31", "대하 30:21-23", "대하 25:26", "행 2:42, 46, 47", "시 36:10", "아 3:4", "대하 29:18", "고전 10:3-5, 12", "시 1:14", "고전 11:25-26", "행 42, 46", "아 5:1-6", "시 123:1-2", "시 13:5, 8", "시 93:3-5", "대하 30:18-19", "사 1:16, 18", "고후 7:11", "대상 15:12-14"] },
  { number: 176, question: "세례와 성찬은 어디에서 일치합니까?", answer: "세례와 성찬은 다음에서 일치합니다. 첫째로, 두 성례를 제정하신 분이 하나님이십니다. 둘째로, 두 성례의 신령한 부분이 그리스도와 그분의 유익입니다. 셋째로, 두 성례는 동일한 언약의 인이며 넷째로, 오직 복음 사역자가 집행해야 하고 다른 사람이 집행해서는 안 되며, 다섯째로, 그리스도께서 다시 오실 때까지 그분의 교회에서 계속되어야 합니다.", references: ["마 28:19", "고전 11:23", "롬 6:3-4", "고전 10:16", "롬4:11", "고전 2:12", "마 26:26-28", "요 1:33", "마 28:19", "고전 11:23", "고전4:1", "히 5:4", "마 28:19-20"] },
  { number: 177, question: "세례와 성찬은 어디에서 서로 다릅니까?", answer: "세례와 성찬은 다음에서 서로 다릅니다. 세례는 한 번, 물로써 시행하여 우리가 거듭남과 그리스도와 연합됨을 표하고 인 치며 심지어 유아에게도 베푸는 반면에, 성찬은 자주, 떡과 포도주로써 시행하여 그리스도께서 영혼의 신령한 양식과 음료이심을 드러내고 나타내며 그 분 안에 우리가 계속 거하고 자랄 것을 확정하고 자기를 살필 나이와 능력을 갖춘 이들에게만 베풉니다.", references: ["마 3:11", "딛 3:5", "갈 3:27", "창 17:7, 9", "행 2:3, 39", "고전 7:14", "고전 11:23-26", "고전 10:16", "고전 11:28-29"] },
  { number: 178, question: "기도가 무엇입니까?", answer: "기도는 그리스도의 이름으로 성신의 도움을 의지하여 우리의 소원을 하나님께 올려 드리는 것인데, 우리의 죄를 고백하고 그분의 자비하심을 깨달아서 감사하며 드리는 것입니다.", references: ["시 62:8", "요 16:23", "롬 8:26", "시 32:5∼6", "단 9:4", "빌 4:6"] },
  { number: 179, question: "우리가 오직 하나님께만 기도해야 합니까?", answer: "오직 하나님께서만 마음을 감찰하시며 간구를 들으시며 죄를 사하시며 모든 이의 소원을 채워 주실 수 있고, 오직 그분만 우리가 믿고 경건하게 예배드려야 할 분이시므로, 경건한 예배의 특별한 부분인 기도는, 모든 사람이 오직 그분께만 드리고 다른 누구에게도 드려서는 안 됩니다.", references: ["왕상 8:39", "행 1:24", "롬 8:27", "시 65:2", "미 7:18", "사 145:18-19", "롬 10:14", "마 4:10", "고전 1:2", "시 1:15", "롬 10:14"] },
  { number: 180, question: "그리스도의 이름으로 기도하는 것이 무엇입니까?", answer: "그리스도의 이름으로 기도하는 것은 그분의 명령에 순종하고 그분의 약속을 확신하면서 그분으로 말미암아 자비를 구하는 것입니다. 그저 그분의 이름만을 언급하는 것이 아니고 그리스도와 그분의 중보 사역으로부터 기도할 마음과 우리의 담대함과 힘과 기도를 들어주시리라는 소망을 얻으면서 구하는 것입니다.", references: ["요 14:13-14", "요 16:24", "단 9:17", "마 7:21", "히 4:14-18", "요일 5:13-15"] },
  { number: 181, question: "왜 우리가 그리스도의 이름으로 기도해야 합니까?", answer: "인생이 심히 죄악되고 그로 말미암아 하나님으로부터 멀리 떠나 있어서 우리가 중보자 없이는 하나님 앞에 가까이 이를 수 없고 하늘에나 땅에나 오직 그리스도 외에는 저 영광스런 일에 임명받거나 적합한 이가 없기 때문에 우리는 다른 이름으로가 아니라 오직 그분의 이름으로만 기도해야 합니다.", references: ["요 14:6", "사 59:2", "엡 3:12", "요 6:27", "히 7:25∼27", "딤전 2:5", "골 3:17", "히 13:15"] },
  { number: 182, question: "성신은 어떻게 우리가 기도하도록 도우십니까?", answer: "우리가 마땅히 빌 바를 알지 못하기 때문에 성신은 우리의 연약함을 도우시되, 누구를 위하여 무엇을 어떻게 기도해야 하는지 깨닫게 하시고, 우리 마음에 (모든 사람이 언제든지 똑같은 것은 아니지만) 기도를 바르게 드리는 데에 필요한 깨달음과 심정과 은덕을 불러일으키고 활발하게 하심으로써 도우십니다.", references: ["롬 8:26-27", "시 10:17", "스 12:10"] },
  { number: 183, question: "누구를 위하여 우리는 기도해야 합니까?", answer: "우리는 지상에 있는 그리스도의 전체 교회를 위하여 관원들과 사역자들을 위하여 우리 자신과 우리 형제들, 또한 우리 원수를 위하여 그리고 현재 살아 있는 사람들과 앞으로 살아갈 모든 사람을 위하여 기도해야 합니다. 그러나 죽은 자들과 사망에 이르는 죄를 범한 것으로 드러난 사람들을 위하여 기도해서는 안 됩니다.", references: ["엡 6:18", "시 28:9", "딤전 2:1-2", "골 4:3", "창 32:11", "약 5:16, 5:44", "딤전 2:1-2", "요 17:20", "삼하 7:29, 12:21-23", "요일 5:16"] },
  { number: 184, question: "무엇을 위하여 우리는 기도해야 합니까?", answer: "우리는 하나님의 영광을 위하는 모든 일과 교회의 안녕과 우리 자신이나 다른 이들의 유익을 위하여 기도해야 합니다. 그러나 불법적인 것을 위하여 기도해서는 안 됩니다.", references: ["마 6:9", "시 51:18, 122:6", "마 7:11", "시 125:4", "요 5:14"] },
  { number: 185, question: "우리는 어떻게 기도해야 합니까?", answer: "우리는 기도할 때에 하나님의 위엄을 깨닫고서 두려워하고, 우리 자신의 무가치함과 가난함과 죄를 깊이 깨달아야 하며, 회개하고 감사하며 넓어진 마음을 가져야 하고, 깨달음과 믿음과 진실함과 열정과 사랑과 인내와 하나님을 기다림이 있어야 하며, 그분의 뜻에 겸손히 순복해야 합니다.", references: ["전 5:1", "창 18:27", "창 32:10", "눅 15:17-19", "눅 18:13-14", "시 51:17", "빌 4:6", "삼상 1:15", "삼상 2:1", "고전 14:15", "막 11:24", "약 1:6", "시 145:18", "시 17:1", "약 5:16", "딤전 2:8", "엡 6:18", "미 7:7", "마 26:39"] },
  { number: 186, question: "우리의 의무인 기도를 지도하시려고 하나님께서 우리에게 주신 법칙은 무엇입니까?", answer: "하나님의 모든 말씀이 우리의 의무인 기도를 지도하기에 유용합니다. 다만 특별한 법칙은 우리 구주 그리스도께서 제자들에게 가르쳐 주신 기도 곧 일반적으로 ‘주님께서 가르치신 기도’라 부르는 것입니다.", references: ["요일 5:14", "마 6:9-13", "눅 11:2-4"] },
  { number: 187, question: "주님께서 가르치신 기도는 어떻게 사용해야 합니까?", answer: "주님께서 가르치신 기도는 우리가 기도를 드릴 때에 따라야 하는 모범으로서 우리의 기도를 지도합니다. 또한 그 자체가 하나의 기도로서 사용될 수 있습니다. 우리가 기도의 의무를 바르게 행하는 데에 필요한 깨달음과 믿음과 경외심과 그 밖의 은혜들로써 주님께서 가르치신 기도를 드릴 수 있습니다.", references: ["마 6:9", "눅 11:2"] },
  { number: 188, question: "주님께서 가르치신 기도는 몇 부분으로 되어 있습니까?", answer: "주님께서 가르치신 기도는 세 부분으로 곧 머리말과 간구들과 맺음말로 되어 있습니다.", references: [] },
  { number: 189, question: "주님께서 가르치신 기도의 머리말이 우리에게 가르치는 것은 무엇입니까?", answer: "‘하늘에 계신 우리 아버지’라는 기도의 머리말은 우리가 기도로써 하나님께 가까이 나아갈 때에 아버지로서 하나님의 선하심과 그 선하심을 누릴 수 있는 우리의 분깃을 확신하고, 경외심과 더불어 자녀로서 합당한 모든 태도를 지니고, 하늘에 속한 것을 바라는 심정을 품고, 하나님의 주권적 능력과 위엄과 은혜로운 겸양을 정당히 깨달음으로써 나아갈 것을 가르칩니다. 또한 우리가 다른 사람들과 함께, 또한 그들을 위하여 기도할 것을 가르칩니다.", references: ["마 6:9", "눅 11:13", "롬 8:15", "사 64:9", "시 123:1", "렘 3:41", "사 63:15-16", "느 1:4-6", "행 12:5"] },
  { number: 190, question: "첫째 간구로 우리는 무엇을 구합니까?", answer: "“이름이 거룩히 여김을 받으시옵소서”라는 첫째 간구로 우리는 우리 자신과 모든 사람 안에 하나님을 올바르게 공경할 만한 능력과 성향이 전혀 없음을 인정하고서, 하나님께서 그분의 은혜로써 우리와 다른 사람들로 하여금 하나님과 하나님의 칭호와 속성과 규례와 말씀과 사역과 무릇 그분이 자기를 알리려고 쓰시는 모든 것을 알고, 인정하고, 높이며, 생각과 말과 행위에서 하나님을 영화롭게 할 수 있는 능력과 심정을 주시기를 구합니다. 또한 우리는 하나님께서 무신론과 무지와 우상 숭배와 신성 모독과 무릇 그분을 욕되게 하는 모든 것을 방지하고 제거해 주시고, 하나님의 통치하시는 섭리로써 하나님의 영광을 위하여 모든 것을 지도하시고 처결하여 주시기를 구합니다.", references: ["마 6:9", "고후 3:5", "시 51:15", "시 67:2-3", "시 83:18", "시 86:10-12, 15", "살후 3:1", "시 147:19-20", "시 138:1-3", "고후 2:14-15", "시 145:1-21", "시 19:14", "시 103:1", "빌 1:9, 11", "시 67:1-4", "엡 1:17-18", "시 97:7", "시 74:18, 22, 23", "왕하 19:15-16", "대하 20:6, 10-12", "시 83:1-18", "시 140:4, 8"] },
  { number: 191, question: "둘째 간구로 우리는 무엇을 구합니까?", answer: "“나라이 임하옵소서”라는 둘째 간구로 우리는 우리 자신과 온 인류가 본성적으로 죄와 사탄의 지배 아래 있음을 인정하면서, 죄와 사탄의 나라가 멸망하고, 복음이 온 세상에 전파되고, 유대인들이 부르심을 받고, 이방인의 충만한 수가 들어오고, 교회가 복음의 사역자들과 규례들로 온전히 구비되며 부패함으로부터 정결하게 되며 세상 권세자들에게서 후원과 지지를 받기를 구합니다. 또한 우리는 그리스도의 규례가 순전하게 시행되어,여전히 죄 가운데 있는 자들을 회심하게 하는 일에, 그리고 이미 회심한 자들을 굳게 하고 위로하고 세우는 일에 효과 있게 하여 주시기를 구하고, 그리스도께서 여기서 우리 마음에서 통치하시고, 주님이 재림하셔서 우리가 주님과 함께 영원히 다스릴 그때가 속히 오게 하여 주실 것을 구합니다. 그리고 우리는 하나님께서 흔쾌히 주님의 능력의 나라를 온 세상에 드러내셔서 이 모든 목적이 가장 잘 이루어지게 하실 것을 구합니다.", references: ["마 6:10", "엡 2:2-3", "시 68:1", "계 12:9", "살후 3:1", "시 67:2", "롬 10:1", "롬11:25", "시 67:1-7", "마 9:38", "엡 5:26-27", "말 1:11", "고후 4:2", "행 26:18", "살후 2:16-17", "엡 3:14, 17", "계 22:20", "사 64:1, 2", "대하 20:6, 10-12"] },
  { number: 192, question: "셋째 간구로 우리는 무엇을 구합니까?", answer: "“뜻이 하늘에서 이룬 것같이 땅에서도 이루어지이다”라는 셋째 간구로 우리는 우리와 모든 사람이 본성적으로 하나님의 뜻을 알고 행하는 일에 전혀 능력도 없고 의향도 없을 뿐만 아니라, 그분의 말씀을 거역하거나 그분의 섭리에 불평하고 원망하기 잘하고, 육신과 마귀의 뜻을 행하려는 성향뿐인 것을 인정하고서, 하나님께서 성신으로 우리 자신과 다른 사람들에게서 마음의 모든 어둠과 연약함과 게으름과 패역함을 제거하시고, 하나님의 은혜로써 모든 일에 하나님의 뜻을 알고 행하고 순종하되, 천사들이 하늘에서 하는 것처럼 동일한 겸손과 즐거움과 신실함과 부지런함과 열심과 진실함과 일관됨을 가지고 행할 능력과 심정을 주시기를 구합니다.", references: ["마 6:10", "롬 7:18", "욥 21:14", "고전 2:14", "롬 8:17", "출 17:7", "민 14:2", "엡 2:2", "엡 1:17-18", "엡 3:16", "마 26:40-41", "렘 31:18-19", "시 119:1, 8, 35, 36", "행 21:14", "미 6:8", "시 100:2", "욥 1:21", "삼하 15:25-26", "사 38:3", "시 119:4-5", "롬 12:11", "시 119:80", "시119:112", "사 6:23", "시 103:20-21", "마 18:10"] },
  { number: 193, question: "넷째 간구로 우리는 무엇을 구합니까?", answer: "“오늘날 우리에게 일용할 양식을 주옵소서”라는 넷째 간구로 우리는 아담 안에서 그리고 우리 자신의 죄로 말미암아 이생의 모든 외적인 복을 누릴 권리를 상실하였고, 하나님께서 이 모든 복을 우리에게서 다 빼앗아 가셔도 마땅하고, 우리가 이용하는 모든 복이 우리에게 저주가 되어도 마땅함을 시인하며, 또한 그것들이 스스로 우리를 붙들어 줄 수도 없고, 우리가 그것들을 누릴 자격을 갖추거나 스스로 노력하여 그것들을 얻을 수 없으며, 오히려 그것들을 불법적으로 원하고 얻고 사용하기 쉬움을 인정하고서, 우리 자신과 다른 사람을 위하여 기도하기를, 그들과 우리 모두가 매일 하나님의 섭리를 기다리면서 합법적인 수단을 사용하여 그분의 거저 주시는 선물로 말미암아 아버지로서 베푸시는 그분의 지혜에 가장 선하게 그것들을 충분히 누릴 수 있기를 구합니다. 또한 우리는 주신 것을 거룩하고 자비롭게 사용하여 우리에게 그것이 계속 있고 복된 것이 되고, 우리가 그것으로 만족할 수 있기를 구하고, 우리가 우리의 현세적인 도움과 위로와 반대되는 모든 것들에서 지키심을 받기를 구합니다.", references: ["마 6:11", "창 2:17", "롬 8:20-22", "렘 5:25", "신 28:15-68", "창 32:10", "신 8:17-18", "렘 6:13", "막 7:21-22", "호 12:7", "약 4:3", "창 43:12-14", "창 28:20", "엡 4:28", "살전 3:11-12", "빌 4:6", "딤전 4:3-5", "딤전 6:6-8", "잠 30:8-9"] },
  { number: 194, question: "다섯째 간구로 우리는 무엇을 구합니까?", answer: "“우리가 우리에게 죄지은 자를 사하여 준 것같이 우리의 죄를 사하여 주옵소서”라는 간구로 우리는 우리와 다른 모든 사람이 원죄와 자범죄를 범했고, 그리하여 하나님의 의에 빚진 자가 된 것을 시인하고, 우리든지 다른 어떤 피조물이든지 그 빚을 조금도 갚을 수 없음을 인정하고서, 우리 자신과 다른 사람을 위하여 기도하기를, 하나님께서 그분의 거저 베푸시는 은혜로 말미암아 믿음으로 획득되고 적용되는 그리스도의 순종과 만족게 하심을 통하여 우리가 받아야 하는 죄의 책임과 형벌을 면제하여 주시고, 하나님의 사랑하시는 자 안에서 우리를받아 주시고, 하나님의 사랑과 은혜를 우리에게 계속 베푸시고, 우리의 매일의 실패를 용서하시고, 날마다 사죄의 확신을 더욱 우리에게 주셔서 우리를 평강과 기쁨으로 가득 채워 주시기를 구합니다. 그리고 우리가 마음으로부터 다른 사람의 죄를 용서한다는 이 증언을 우리 안에 갖고 있을 때에, 더욱 담대하게 이 간구를 드리고 기대할 용기를 가지게 됩니다.", references: ["마 6:12", "롬 3:9-22", "마 18:24-25", "시 130:3-4", "롬 3:24-26", "히 9:22", "엡 1:67", "벧후 1:2", "호 14:2", "렘 14:7", "롬 15:13", "시 151:7-10, 12", "눅 11:4", "마 6:14-15"] },
  { number: 195, question: "여섯째 간구로 우리는 무엇을 구합니까?", answer: "“우리를 시험에 들지 말게 하옵시며 다만 악에서 구하옵소서”라는 여섯째 간구로 우리는 지극히 지혜로우시고 의로우시고 은혜로우신 하나님께서 여러 가지 거룩하고 정의로운 목적으로 일들을 정하셔서 우리가 시험에 공격받고 당황하고 잠시 사로잡히게 될 수도 있는 것을 시인하고, 사탄과 세상과 육신이 강력하게 우리를 빗나가게 하고 우리를 사로잡으려고 준비하고 있는 것을 인정하며, 우리가 우리 죄 사함 받은 후에라도 우리의 부패함과 연약함과 깨어 있지 못함으로 말미암아 시험을 받기도 하고 스스로 시험에 떨어지기도 할 뿐만 아니라 스스로는 시험에 맞서고 시험에서 회복되고 시험을 선용할 능력도 의향도 없어서 시험의 권세 아래 방치되어도 마땅한 것을 시인합니다. 우리는 하나님께서 세상과 그 속의 모든 것을 다스려 주시며 육신을 정복하시며 사탄을 억제해 주시고, 만사를 정하시고, 은혜의 모든 수단들을 내려 주시며 그것들에 복 주시고, 우리를 살리사 깨어 이 수단들을 사용하게 하여 주시기를 구합니다. 또한 우리는 우리와 그분의 모든 백성이 그분의 섭리로 말미암아 시험 받아 죄를 짓지 않도록 지키심을 받고, 혹 시험 받았더라도 그분의 성신으로 우리가 시험의 때에 설 수 있게 강력한 지지와 능력을 받게 하시고, 혹 넘어졌을 때라도 다시 일으킴 받아 시험에서 회복되어서 그 경험을 거룩하게 이용하여 향상되게 해 주시기를 구합니다. 그리고 우리는 우리의 성화와 구원이 완전해지고, 사탄이 우리 발아래서 짓밟히고, 우리가 영원히 죄와 시험과 모든 악으로부터 완전히 자유롭게 되기를 구합니다.", references: ["마 6:13", "대하 32:31", "대상 21:1", "눅 21:34", "막 4:19", "약 1:14", "갈 5:17", "마 26:41", "마 26:69-72", "갈 2:11-14", "대하 18:3", "대하 19:2", "롬 7:23-24", "대상 21:1-4", "대하 16:7-10", "시 18:11-12", "요 17:15", "시 51:10", "시119:133", "대하 12:7-8", "고전 10:12-13", "히 13:20-21", "마 26:41", "시 19:13", "엡 3:14-17", "살전 3:13", "유1: 24", "시 51:12", "벧전 5:8-10", "고후 13:7, 9", "롬 16:20", "스 3:2", "눅 22:31-32", "요 17:15", "살전 5:23"] },
  { number: 196, question: "주님께서 가르치신 기도의 맺음말은 우리에게 무엇을 가르칩니까?", answer: "“대개 나라와 권세와 영광이 아버지께 영원히 있사옵나이다. 아멘”이라는 주님께서 가르치신 기도의 맺음말은 우리가 간구 드리는 이유를 우리 자신이나 다른 어떤 피조물에게 있는 무슨 가치가 아니라 오직 하나님으로부터 취하고, 오직 하나님께만 영원한 주권과 전능하심과 영광스러운 덕을 돌림으로써 기도할 때에 찬송하여, 우리의 간구가 힘 있게 되도록 가르칩니다. 그러므로 하나님께서 우리를 능히 도우실 수도 있고 기꺼이 도우실 뜻도 있으니 우리는 믿음으로 말미암아 더욱 담대하여져서 하나님께서 그리하여 주실 것을 간구하고, 하나님께서 우리의 간구를 이루어주시기를 잠잠히 신뢰할 수 있습니다. 그리고 우리의 이런 소원과 확신을 표시하기 위하여 우리는 “아멘” 하고 말합니다.", references: ["Mt 6:13, Ro 15:30, Da 9:4, 7-9, 16-19, Php 4:6, 1 Ch 29:10-13, Eph3:20-21, Lk 11:13, 2Ch 20:6, 11, 14:11, 1Co 14:16, Rev 22:20-21"] },
];
